import type { Drill } from "./types";

// Student / mid (Undergraduate) drills, keyed by module slug — 25 per module.
// Persona: an undergraduate university student — seminars, group projects,
// emails to professors and advisors, internship applications, club leadership.
// Merged into course.ts.
export const STUDENT_MID_DRILLS: Record<string, Drill[]> = {
  "lead-with-the-point": [
    {"id":"lead-stu-mid-01","level":"mid","profession":"student","title":"The extension request that circles","scenario":"You need a two-day extension on your history paper because you were sick for most of the week. Your draft email to the professor opens with three sentences about how much you enjoy the course before mentioning the deadline.","task":"Write a 2-3 sentence email that puts the extension request and new date in the first sentence.","tips":["Sentence one: the ask and the specific date you're proposing.","The reason comes second, in one sentence.","Cut the compliments — they read as padding before an ask."],"focus":["clarity","structure"],"placeholder":"I'm writing to request a two-day extension on the primary-source paper, to Friday the 14th."},
    {"id":"lead-stu-mid-02","level":"mid","profession":"student","title":"The group chat status dump","scenario":"You finished your section of the group presentation and added it to the shared slides. Your draft message to the group chat narrates everything you struggled with before saying the part is done.","task":"Write a 1-2 sentence group chat message that leads with the headline.","tips":["First words: your section is done and where to find it.","Skip the story of how hard it was.","Add what you need from others only if it's one line."],"focus":["concision","clarity"]},
    {"id":"lead-stu-mid-03","level":"mid","profession":"student","title":"The office-hours wind-up","scenario":"You have five minutes in a crowded office-hours queue. Your real question is whether problem 4 wants a proof or just a counterexample, but you tend to open by recapping the whole problem set.","task":"Script the first two sentences you'd say, leading with the question itself.","tips":["Ask the question in sentence one, naming the problem number.","Give only the context needed to answer it.","A crisp question gets you an answer before your time runs out."],"focus":["clarity","concision"],"placeholder":"Quick question on problem 4: does 'show' mean a full proof, or is a counterexample enough?"},
    {"id":"lead-stu-mid-04","level":"mid","profession":"student","title":"The form that needs a signature","scenario":"You need your advisor's signature on a course-change form before the registrar's Friday deadline, and they answer email slowly. Your draft spends a paragraph explaining why you're switching sections first.","task":"Write a 2-3 sentence email that leads with the ask and the deadline.","tips":["First sentence: what you need signed and by when.","Offer the easiest path — attach the form, offer to drop by.","The why can be one clause, not a paragraph."],"focus":["clarity","impact"],"placeholder":"Could you sign the attached course-change form before Friday's registrar deadline?"},
    {"id":"lead-stu-mid-05","level":"mid","profession":"student","title":"The recommendation letter ask","scenario":"You're asking a professor you had two semesters ago for a recommendation letter for a summer research program. The deadline is in three weeks. Your draft buries the actual ask under a long reintroduction of who you are.","task":"Write an email opening (2-3 sentences) that states the ask and deadline first, then the reminder of who you are.","tips":["Lead with the request and the due date.","Then one sentence placing yourself: course, semester, what you wrote or did.","Professors get many of these — make yours instantly parseable."],"focus":["structure","clarity"],"placeholder":"Would you be willing to write me a recommendation for the SURF program, due March 21?"},
    {"id":"lead-stu-mid-06","level":"mid","profession":"student","title":"The seminar point that never lands","scenario":"In your political theory seminar you want to argue that the author contradicts herself between chapters two and five. You tend to talk through your whole chain of reading before stating the claim, and the discussion moves on before you get there.","task":"Script a 2-3 sentence seminar contribution that states your claim in sentence one.","tips":["Open with the claim: 'I think the author contradicts herself between...'","Then give the strongest single piece of evidence.","In live discussion, the point must come before the windup."],"focus":["clarity","structure"]},
    {"id":"lead-stu-mid-07","level":"mid","profession":"student","title":"The presentation that opens with process","scenario":"You're presenting your team's market-research findings to the class. Your current opening slide narrates the timeline: 'First we designed a survey, then we collected responses...' The finding — students would pay for late-night food delivery — comes at minute six.","task":"Write the first two sentences of the presentation, leading with the finding.","tips":["Open with the result the audience should remember.","The method matters, but as support, not the headline.","If people check out at minute two, they should still know your point."],"focus":["impact","structure"],"placeholder":"Our survey of 212 students found that two-thirds would pay a delivery fee for food after 10pm."},
    {"id":"lead-stu-mid-08","level":"mid","profession":"student","title":"The regrade request that hides the point","scenario":"You believe question 3 on your midterm was graded against the wrong rubric line — you gave the answer the rubric asks for but lost four points. Your draft email to the TA opens with a general reflection on how the exam went.","task":"Write a 2-3 sentence email that names the question, the points, and the ask in the first sentence.","tips":["Lead with the specific request: question 3, four points, please re-check.","Cite the rubric line as your one piece of support.","Keep the tone factual, not aggrieved."],"focus":["clarity","precision"]},
    {"id":"lead-stu-mid-09","level":"mid","profession":"student","title":"The meeting-change announcement","scenario":"Your club's Thursday meeting has to move to Room 210 at 7pm because the usual room is booked for exams. Your draft announcement opens with apologies and the backstory about room scheduling.","task":"Write a 1-2 sentence announcement that leads with the new time and place.","tips":["First line: new day, time, room — the part people must retain.","One short sentence of why, if any.","People skim announcements; front-load the change."],"focus":["clarity","concision"],"placeholder":"This week's meeting moves to Thursday 7pm, Room 210."},
    {"id":"lead-stu-mid-10","level":"mid","profession":"student","title":"The slipped deadline you're dreading","scenario":"You promised your project group your literature review section by Sunday, and it won't be ready until Tuesday. You're embarrassed, so your draft message explains your week before admitting the new date.","task":"Write a 2-3 sentence message that states the new date up front.","tips":["Lead with the new date — that's what the group plans around.","One sentence of reason, no saga.","Offer something concrete: an outline now, the full draft Tuesday."],"focus":["clarity","impact"]},
    {"id":"lead-stu-mid-11","level":"mid","profession":"student","title":"The typo in the problem set","scenario":"You found what looks like an error in problem 2 of this week's problem set — the matrix given isn't invertible, so part (b) can't be solved as written. You want to email the professor but your draft hedges for three sentences before naming the issue.","task":"Write a 2-sentence email that leads with the specific issue.","tips":["First sentence: problem 2(b) appears unsolvable as written, and why in a phrase.","Ask the one clarifying question you need.","Being direct about a possible error is helpful, not rude."],"focus":["precision","clarity"],"placeholder":"I think there may be an error in problem 2(b): the matrix in part (a) isn't invertible, so the inverse in (b) doesn't exist."},
    {"id":"lead-stu-mid-12","level":"mid","profession":"student","title":"The coffee-chat request to an alum","scenario":"A recent graduate from your program now works at a company you want to intern for. You found them through the alumni directory. Your draft LinkedIn message spends four sentences on your background before asking for anything.","task":"Write a 3-sentence message that puts the ask — a 20-minute call — in the first sentence.","tips":["Lead with who you are in a phrase and what you're asking for.","One sentence on why them specifically.","Make it easy to say yes: offer times, keep it short."],"focus":["clarity","audience"]},
    {"id":"lead-stu-mid-13","level":"mid","profession":"student","title":"The interview answer that starts at the beginning","scenario":"An interviewer asks, 'Tell me about a project you're proud of.' Your instinct is to start with how the course was structured and how groups were assigned. The impressive part — your team's app won the class demo day — comes ninety seconds in.","task":"Script the first two sentences of your answer, leading with the outcome.","tips":["Open with the result: what you built and what it achieved.","Then rewind briefly for context.","Interviewers decide fast — put the proof up front."],"focus":["impact","structure"],"placeholder":"My team built a course-planning app that won our class demo day out of fourteen teams."},
    {"id":"lead-stu-mid-14","level":"mid","profession":"student","title":"The career-center ask with a clock on it","scenario":"An internship application closes Friday and you want the career center to review your resume before you submit. Your draft email describes the company and the role for a paragraph before asking whether anyone has time this week.","task":"Write a 2-3 sentence email that leads with the ask and the Friday deadline.","tips":["First sentence: resume review needed before Friday — is there a slot?","Name the one thing you want checked if you can.","Deadline-driven asks should announce the deadline immediately."],"focus":["clarity","concision"]},
    {"id":"lead-stu-mid-15","level":"mid","profession":"student","title":"The presentation-slot swap","scenario":"You're scheduled to present in Tuesday's section, but you have a medical appointment that can't move. You want to ask a classmate to swap slots with you for Thursday. Your draft opens with a long apology about asking a favor.","task":"Write a 2-sentence message that leads with the specific swap you're proposing.","tips":["Sentence one: the exact trade — my Tuesday for your Thursday.","One clause of reason is plenty.","Clear asks are easier to grant than apologetic ones."],"focus":["clarity","concision"],"placeholder":"Would you swap presentation slots with me — you take Tuesday, I take your Thursday?"},
    {"id":"lead-stu-mid-16","level":"mid","profession":"student","title":"The lab update your PI skims","scenario":"You're an undergraduate research assistant. Your weekly email to your PI describes every step you took at the bench, and the actual result — the assay finally worked at the new concentration — is in the last paragraph. Your PI reads these on their phone.","task":"Write a 2-3 sentence update that leads with the result.","tips":["First sentence: the finding, with the key number.","What you tried is supporting detail below.","Write for a reader who may only see the first line."],"focus":["structure","precision"],"placeholder":"The assay worked at 2.5 µM — clean signal in all three replicates."},
    {"id":"lead-stu-mid-17","level":"mid","profession":"student","title":"The financial-aid question buried in worry","scenario":"You submitted a required verification document to financial aid two weeks ago and your portal still shows 'missing.' Your draft email narrates your anxiety about tuition before asking whether the document was received.","task":"Write a 2-sentence email that asks the question first.","tips":["Sentence one: the question — was the document received on [date]?","Include the identifying details they need: name, ID, document, date sent.","Offices process faster when the ask is instantly clear."],"focus":["clarity","precision"]},
    {"id":"lead-stu-mid-18","level":"mid","profession":"student","title":"The discussion post that finds its thesis late","scenario":"Your weekly discussion post for your sociology course is graded on argument quality. Your draft summarizes the reading for two paragraphs, and your actual position appears in the final sentence.","task":"Write the opening 1-2 sentences of the post, stating your position first.","tips":["Open with your claim about the reading, not a summary of it.","The professor reads forty of these — reward them in line one.","Summary earns no points; argument does."],"focus":["structure","impact"],"placeholder":"The author's argument depends on an assumption she never defends:"},
    {"id":"lead-stu-mid-19","level":"mid","profession":"student","title":"The found-it message","scenario":"Your project group has spent two days hunting for a public dataset with city-level rent prices. You just found one that fits. Your draft message walks through your whole search history before sharing the link.","task":"Write a 1-2 sentence message that leads with the find.","tips":["First words: found it — here's the link and what it covers.","Say in a phrase why it fits the need.","Nobody needs the story of the search."],"focus":["concision","clarity"]},
    {"id":"lead-stu-mid-20","level":"mid","profession":"student","title":"The study-abroad credit question","scenario":"You're deciding whether to apply for a semester in Copenhagen, and the whole decision hangs on one question: will the economics courses there count toward your major? Your draft email to the study-abroad office is three paragraphs of your situation with the question at the end.","task":"Write a 2-3 sentence email that puts the question in the first sentence.","tips":["Lead with the single question that decides everything.","Give the two facts they need: your major, the program name.","One clear question invites one clear answer."],"focus":["clarity","concision"],"placeholder":"Will economics courses taken through the Copenhagen exchange count toward the economics major?"},
    {"id":"lead-stu-mid-21","level":"mid","profession":"student","title":"The budget request to student government","scenario":"Your robotics club needs $800 from the student activities fund for competition registration and travel. The funding committee reads dozens of requests. Your draft opens with the club's founding story.","task":"Write the first two sentences of the request, leading with the amount and purpose.","tips":["Sentence one: the amount and exactly what it buys.","Sentence two: the strongest reason it's worth funding.","Committees skim — the number and purpose must be unmissable."],"focus":["clarity","impact"],"placeholder":"The Robotics Club requests $800 to cover registration and travel for the regional competition on April 12."},
    {"id":"lead-stu-mid-22","level":"mid","profession":"student","title":"The missed meeting recovery","scenario":"You missed a scheduled meeting with your professor yesterday — you mixed up the time. Your draft email is five sentences of apology before you get to what you actually want: to reschedule.","task":"Write a 2-3 sentence email that apologizes once, briefly, and leads to the reschedule ask fast.","tips":["One sentence: own the miss without a paragraph of self-criticism.","Move immediately to the ask: two specific times you can make.","Over-apologizing makes the reader manage your feelings."],"focus":["clarity","concision"]},
    {"id":"lead-stu-mid-23","level":"mid","profession":"student","title":"The peer review that buries the verdict","scenario":"You're peer-reviewing a classmate's essay draft. Your honest read: the argument is strong but the second half drifts off the thesis. Your draft feedback lists small line edits for two paragraphs before mentioning the structural issue.","task":"Write the first two sentences of your feedback, leading with the most important point.","tips":["Open with the one change that matters most.","Say what's working in the same breath — briefly and honestly.","Line edits come after the big point, or they'll be all that gets fixed."],"focus":["structure","impact"]},
    {"id":"lead-stu-mid-24","level":"mid","profession":"student","title":"The shift-swap text","scenario":"You work part-time at the campus library and need to swap your Tuesday evening shift to study for a midterm. Your draft text to your supervisor explains your whole exam schedule before proposing anything.","task":"Write a 1-2 sentence message that leads with the proposed swap.","tips":["First sentence: the exact proposal — drop Tuesday, cover Thursday.","Reason in one clause.","Make the yes easy: you've already found the coverage if you can."],"focus":["clarity","concision"],"placeholder":"Could I swap my Tuesday 6-9 shift for Thursday? Priya has agreed to cover if you approve."},
    {"id":"lead-stu-mid-25","level":"mid","profession":"student","title":"The poster-session opener","scenario":"You're presenting your first research poster at the undergraduate symposium. Visitors drift past every thirty seconds. Your current opening walks through your methods section left to right; most people leave before the conclusion panel.","task":"Script a 1-2 sentence opener that gives the takeaway first.","tips":["Lead with the finding in plain words.","Then offer the tour: 'Happy to walk you through how we got there.'","A passerby should get the point even if they leave in fifteen seconds."],"focus":["impact","clarity"],"placeholder":"We found that campus food-pantry use triples in the two weeks before finals — here's the data."}
  ],
  "start-with-the-audience": [
    {"id":"audience-stu-mid-01","level":"mid","profession":"student","title":"The class project, explained to a recruiter","scenario":"At a career fair, a recruiter asks about the project on your resume. Your practiced answer is course-speak: 'It was our CS 3200 final where we implemented a normalized schema with a Flask front end.' The recruiter isn't technical and is deciding whether to keep talking to you.","task":"Rewrite your 2-3 sentence answer for a listener who cares about what you can do, not the course number.","tips":["Drop the course number — it means nothing outside campus.","Translate the tech into what the thing does for a user.","End with what you owned personally."],"focus":["audience","impact"],"placeholder":"I built a tool that lets students plan four years of courses in one screen —"},
    {"id":"audience-stu-mid-02","level":"mid","profession":"student","title":"The professor email in group-chat voice","scenario":"You drafted an email to your professor asking about the exam format, but it reads like a text to a friend: 'hey quick q, is the final cumulative or nah? also is it open note lol.' The professor is formal and answers 200 students.","task":"Rewrite the email in 2-3 sentences at a register appropriate for a professor you don't know well.","tips":["Match the reader's formality, not your group chat's.","Keep the questions crisp — formality doesn't mean padding.","Include your course and section; they teach more than one."],"focus":["audience","clarity"]},
    {"id":"audience-stu-mid-03","level":"mid","profession":"student","title":"Research night for non-majors","scenario":"Your department showcases student research to visiting families and prospective students. You study antibiotic resistance in soil bacteria. Your current explanation opens with 'horizontal gene transfer via mobile genetic elements' — and you can see eyes glaze.","task":"Write a 2-3 sentence explanation of your research for a smart visitor with no biology background.","tips":["Start from something they already know: antibiotics stop working.","One everyday analogy is worth three technical terms.","Save the vocabulary for whoever asks the follow-up."],"focus":["audience","clarity"]},
    {"id":"audience-stu-mid-04","level":"mid","profession":"student","title":"The activities-fair pitch full of acronyms","scenario":"You're recruiting first-years for the club you help run. Your pitch is insider shorthand: 'We do MUN circuit conferences, mostly GA committees, and we usually place at HNMUN.' First-years don't know any of these letters.","task":"Rewrite the pitch in 2-3 sentences a brand-new student would understand and find appealing.","tips":["Expand or drop every acronym — insiders are not your audience today.","Lead with what a member actually does and gets.","Say what a first-year with zero experience should do next."],"focus":["audience","clarity"],"placeholder":"We're the debate-style club where you represent a country and argue world issues against other schools —"},
    {"id":"audience-stu-mid-05","level":"mid","profession":"student","title":"Catching up the study-group absentee","scenario":"A friend in your statistics study group missed the week where confidence intervals were introduced and is now lost on the homework. You understand the material, but your first attempt at explaining used the lecture's notation and lost her immediately.","task":"Write a 3-4 sentence explanation of what a confidence interval says, pitched at someone a week behind.","tips":["Start where she is, not where the lecture is.","Use a concrete example with real numbers before any notation.","Check the bridge: what did she last understand? Build from there."],"focus":["audience","clarity"]},
    {"id":"audience-stu-mid-06","level":"mid","profession":"student","title":"The coursework-to-cover-letter translation","scenario":"You're applying for a marketing internship. Your cover letter currently says: 'I completed coursework in consumer behavior, market research methods, and integrated marketing communications.' The hiring manager wants to know what you can do, not your transcript.","task":"Rewrite that line as 1-2 sentences framed around what the employer gets.","tips":["Course titles are inputs; employers buy outputs.","Name a concrete thing you produced or analyzed in those courses.","Connect it to work an intern would actually do for them."],"focus":["audience","impact"],"placeholder":"In my market research course I designed and ran a 200-person survey, then turned the results into"},
    {"id":"audience-stu-mid-07","level":"mid","profession":"student","title":"The question with no anchor","scenario":"You email a professor who teaches 200 students: 'I was confused about what you said near the end of class — could you explain it again?' They have no idea which class, which topic, or which part confused you.","task":"Rewrite the email in 2-3 sentences so the professor can answer without asking anything back.","tips":["Anchor it: which lecture, which topic, which specific claim.","Say what you did understand, so they can aim the answer.","Ask one precise question, not 'explain it again.'"],"focus":["audience","precision"]},
    {"id":"audience-stu-mid-08","level":"mid","profession":"student","title":"The treasurer handoff no one can follow","scenario":"You're graduating and handing the club's finances to next year's treasurer, who has never done the job. Your draft handoff note references 'the usual SGA process,' 'the spreadsheet,' and 'what we did after the spring fiasco' — shorthand only you understand.","task":"Rewrite one paragraph (3-4 sentences) of the handoff assuming the reader knows nothing.","tips":["Spell out every piece of shorthand — names, links, locations.","Order it by what they'll need first, not by what you remember first.","Your successor can't ask you questions in October; write for that."],"focus":["audience","structure"]},
    {"id":"audience-stu-mid-09","level":"mid","profession":"student","title":"The gen-ed presentation pitched too high","scenario":"You're a physics major presenting on medical imaging in a gen-ed science course. Half the class hasn't taken math past high school. Your draft opens with the Fourier transform. Your grade partly depends on whether the class can follow you.","task":"Write the first 2-3 sentences of the presentation, calibrated to a non-major audience.","tips":["Open with the question the technology answers: how do we see inside a body?","Pick the one idea they must get, and protect it from the details.","Depth impresses professors; reach impresses this room."],"focus":["audience","impact"],"placeholder":"An MRI machine takes pictures of the inside of your body without ever touching it — here's the trick that makes that possible."},
    {"id":"audience-stu-mid-10","level":"mid","profession":"student","title":"The IT ticket in student-speak","scenario":"Your student portal won't let you register — every time you submit, the page reloads with no error. Your draft to the help desk says 'registration is broken, please fix ASAP.' The help desk needs specifics to route it, and 'broken' tells them nothing.","task":"Rewrite the request in 2-3 sentences with the details a technician needs.","tips":["Describe what you did, what you expected, and what happened instead.","Include the specifics: browser, page, time, student ID.","Write for the person routing tickets, not for your frustration."],"focus":["audience","precision"]},
    {"id":"audience-stu-mid-11","level":"mid","profession":"student","title":"One update, two readers","scenario":"Your group's project hit a snag: the survey tool caps free responses at 100, and you need 250. You need to tell your teammates (who will brainstorm workarounds) and your professor (who cares about the timeline and rigor). One message won't fit both.","task":"Write the 1-2 sentence version for the professor, framed around what they care about.","tips":["The professor's stakes: is the project still sound and on time?","Lead with the impact and your plan, not the tool's pricing tiers.","Pick one primary audience per message — don't average them."],"focus":["audience","clarity"]},
    {"id":"audience-stu-mid-12","level":"mid","profession":"student","title":"The scholarship essay full of campus jargon","scenario":"Your scholarship essay for a national foundation mentions 'FYE seminars,' 'the Honors LLC,' and 'my UTA position.' The reviewers are retired professionals from around the country who have never seen your campus.","task":"Rewrite one 2-3 sentence passage so an outside reviewer understands your roles without translation.","tips":["Replace every campus-specific label with what the thing actually is.","'UTA' becomes 'undergraduate teaching assistant for a 90-student course.'","Jargon reads as thoughtlessness to readers outside the bubble."],"focus":["audience","clarity"],"placeholder":"As an undergraduate teaching assistant for a 90-student introductory chemistry course, I"},
    {"id":"audience-stu-mid-13","level":"mid","profession":"student","title":"Tutoring without the curse of knowledge","scenario":"You tutor a first-year in intro programming. She asks why her loop runs forever. You know instantly — the counter never increments — but your explanation ('your loop invariant never changes so the termination condition is unreachable') made it worse.","task":"Write a 2-3 sentence explanation a brand-new programmer would understand.","tips":["Use her code and her words, not the textbook's.","Trace what the computer does, step by step, in plain language.","The goal is her next bug, not this one: teach the checking habit."],"focus":["audience","clarity"]},
    {"id":"audience-stu-mid-14","level":"mid","profession":"student","title":"The alum who left campus five years ago","scenario":"You're messaging an alum about her consulting job. Your draft says you're 'in Chen's section of the new data track' and 'doing the accelerated capstone.' She graduated five years ago — none of that existed, and none of it matters to her.","task":"Rewrite your 2-3 sentence intro with context she actually has and cares about.","tips":["Describe your program in universal terms: year, major, focus.","Lead with the connection: same major, same club, same hometown.","Ask about her world, which you researched, not yours."],"focus":["audience","clarity"]},
    {"id":"audience-stu-mid-15","level":"mid","profession":"student","title":"Explaining the major switch to your parents","scenario":"You're switching from pre-med to statistics, and you're calling your parents tonight. Your prepared speech is about how much you dislike organic chemistry. Their real worries are different: is this rash, and can you get a job?","task":"Script 2-3 sentences that address their stakes, not just your feelings.","tips":["Answer the question they'll actually be asking themselves.","Bring evidence for their concerns: job outcomes, your plan, who advised you.","Complaining about a course argues you're fleeing; a plan argues you're choosing."],"focus":["audience","impact"],"placeholder":"I've decided to switch to statistics, and I want to walk you through why it's a stronger path for me, not a retreat."},
    {"id":"audience-stu-mid-16","level":"mid","profession":"student","title":"The TA who runs six sections","scenario":"You email your TA: 'I had a question about the assignment — is what I did okay for the second part?' The TA runs six sections across two courses, and your email has no course, no section, no assignment name, and no description of what you did.","task":"Rewrite the email in 2-3 sentences with everything the TA needs to answer in one reply.","tips":["Identify yourself: course, section, assignment.","Describe your approach in a sentence so 'is this okay' has content.","Every missing detail costs a full email round-trip."],"focus":["audience","precision"]},
    {"id":"audience-stu-mid-17","level":"mid","profession":"student","title":"The poster caption only your lab understands","scenario":"Your symposium poster's summary box was written for your lab meeting: 'Knockdown of GENE-X attenuated the phenotype in the F2 generation.' Symposium judges come from every department — the English professor judging your aisle should be able to follow the summary.","task":"Rewrite the 1-2 sentence summary for an educated reader from any field.","tips":["Name the organism and the question in everyday words.","Keep one precise scientific term at most, and gloss it.","The specialist details live in the methods panel, not the summary."],"focus":["audience","clarity"]},
    {"id":"audience-stu-mid-18","level":"mid","profession":"student","title":"The recruitment email that assumes membership","scenario":"Your club's recruitment email to the general student list reads like it's written for existing members: 'Comps are coming up, so join now to get case-prepped before nationals qualifiers.' A curious sophomore has no idea what any of that involves.","task":"Rewrite the 2-3 sentence email for a student who has never heard of the club.","tips":["First contact: what the club does, in plain words, before any insider timeline.","Sell the experience, not the calendar.","One clear next step: come Thursday, no experience needed."],"focus":["audience","impact"],"placeholder":"Ever wanted to argue a business case in front of judges? We're the team that competes at that —"},
    {"id":"audience-stu-mid-19","level":"mid","profession":"student","title":"The nonprofit interview, technical answer","scenario":"You're interviewing for a data internship at a food-bank nonprofit. Asked about your skills, your rehearsed answer is about 'pandas, regression models, and dashboarding in Tableau.' The interviewer is the operations director, not a data person, and cares about hungry families served.","task":"Rewrite your 2-3 sentence answer to land with a mission-driven, non-technical interviewer.","tips":["Translate every tool into the decision it improves.","Connect your skills to their world: routes, donations, waste, families.","Name the tech briefly at the end for credibility, not as the lead."],"focus":["audience","impact"]},
    {"id":"audience-stu-mid-20","level":"mid","profession":"student","title":"The cold email to a lab you want to join","scenario":"You want a research position in a neuroscience lab. Your draft email is entirely about you — your GPA, your courses, your ambitions. It could have been sent to any of forty labs, and the professor can tell.","task":"Rewrite the opening 2-3 sentences so they're unmistakably about this lab's work.","tips":["Name a specific paper or project of theirs and what caught you.","Connect one concrete skill of yours to their methods.","A professor deletes generic; specific gets a reply."],"focus":["audience","impact"],"placeholder":"I read your 2024 paper on sleep and memory consolidation, and the finding that"},
    {"id":"audience-stu-mid-21","level":"mid","profession":"student","title":"Instructions for volunteers who missed the planning","scenario":"Twelve volunteers are helping at your club's charity 5K on Saturday. They weren't at any planning meeting. Your draft instructions reference 'the usual check-in setup' and 'the system we used last year' — context none of them have.","task":"Write a 3-4 sentence instruction message that works for someone with zero prior context.","tips":["Assume nothing: where, when, wear what, do what, ask whom.","Order instructions by their morning, chronologically.","Test it: could a volunteer who joined yesterday execute this alone?"],"focus":["audience","structure"]},
    {"id":"audience-stu-mid-22","level":"mid","profession":"student","title":"The study-abroad statement, misaimed","scenario":"Your study-abroad application essay is written like a travel blog: beaches, food, adventure. The selection committee funds academic programs and is reading for evidence you'll thrive in a rigorous foreign classroom and represent the university well.","task":"Rewrite the opening 2-3 sentences aimed at what the committee is actually selecting for.","tips":["Read the rubric behind the reader: academic fit, maturity, purpose.","Anchor to specific courses or projects only available there.","Enthusiasm helps; enthusiasm aimed at their criteria wins."],"focus":["audience","impact"]},
    {"id":"audience-stu-mid-23","level":"mid","profession":"student","title":"The error report to a non-technical teammate","scenario":"Your group's shared analysis notebook crashes for one teammate. You know why — she's on an old library version — but your explanation ('your environment has a dependency conflict, just rebuild it') left her more stuck than before.","task":"Write a 2-3 sentence message that gets her unstuck without assuming your knowledge.","tips":["Skip the diagnosis vocabulary; give the action.","Number the steps and name the exact buttons or commands.","Offer the fallback: 'or call me and we'll do it together in five minutes.'"],"focus":["audience","clarity"]},
    {"id":"audience-stu-mid-24","level":"mid","profession":"student","title":"The resume bullet nobody outside class understands","scenario":"Your resume says: 'Completed PSYC 3400 capstone utilizing mixed-methods design per course requirements.' A recruiter spends seven seconds per resume and has no idea what you did or whether it was impressive.","task":"Rewrite the bullet in one line framed for a recruiter, not a registrar.","tips":["Cut the course code; lead with the action and scale.","Numbers travel: participants, hours, percentage, rank.","Ask of every word: does a stranger know why this is good?"],"focus":["audience","impact"],"placeholder":"Designed and ran a mixed-methods study of 85 students on exam anxiety, presenting findings to"},
    {"id":"audience-stu-mid-25","level":"mid","profession":"student","title":"The librarian who can't read your mind","scenario":"You approach the research librarian: 'Do you have anything on the economy?' Your actual need is specific — three peer-reviewed sources on minimum-wage effects on teen employment for an eight-page policy paper due in two weeks.","task":"Script a 2-3 sentence request that gives the librarian what they need to actually help.","tips":["Name the assignment, the specific topic, and what counts as a valid source.","Say what you've already found, so they don't repeat it.","Specific requests get expert help; vague ones get the catalog link."],"focus":["audience","precision"]}
  ],
  "structure-that-carries": [
    {"id":"structure-stu-mid-01","level":"mid","profession":"student","title":"The group-project problem pile","scenario":"Your group project is in trouble and you've listed the problems as they occurred to you: Maya missed two meetings, the dataset has gaps, nobody agreed on the citation style, the intro doesn't match the results, the deadline is in nine days, and the shared doc is chaos. You need to raise this at tonight's meeting without it sounding like a rant.","task":"Group the six problems into 2-3 labeled buckets and write the one governing sentence you'd open with.","tips":["Sort into categories like people, content, and process — not chronology.","The governing sentence names the situation and the goal, not a complaint.","Three buckets are memorable; six loose grievances are noise."],"focus":["structure","clarity"],"placeholder":"We have nine days and three fixable problem areas: content gaps, coordination, and consistency."},
    {"id":"structure-stu-mid-02","level":"mid","profession":"student","title":"SCQA for the paper introduction","scenario":"Your politics paper argues that ranked-choice voting reduces negative campaigning. Your current introduction is a paragraph of throat-clearing about democracy in general. Your professor's rubric explicitly rewards a focused setup.","task":"Write a 3-4 sentence introduction using Situation, Complication, Question, Answer.","tips":["Situation: the stable fact everyone accepts.","Complication: what makes it a live problem worth a paper.","Answer is your thesis — put it at the end of the intro, sharp and arguable."],"focus":["structure","impact"]},
    {"id":"structure-stu-mid-03","level":"mid","profession":"student","title":"PREP under a cold call","scenario":"Your seminar professor cold-calls: 'Do you find the author's argument convincing?' You have thirty seconds and a real opinion, but your answers in class tend to wander through everything you noticed before landing anywhere.","task":"Script a 3-4 sentence spoken answer using Point, Reason, Example, Point.","tips":["Point first: convincing or not, in one sentence.","One reason, one concrete example from the text — resist listing three.","Restate the point in fresh words to close; it signals you're done."],"focus":["structure","clarity"],"placeholder":"Mostly convincing, with one gap. The core claim holds because"},
    {"id":"structure-stu-mid-04","level":"mid","profession":"student","title":"Three questions, one email","scenario":"You have three unrelated questions for your professor: whether the final is cumulative, whether you can use a dataset from another course for the project, and how to get your midterm regraded. Your last multi-question email got one answer and two ignored.","task":"Write the email skeleton — an opening line plus a numbered structure — so all three get answered.","tips":["Announce the shape: 'Three quick questions.'","Number them; numbered items are visibly un-answered when skipped.","Order by simplicity — easy yes/no first."],"focus":["structure","concision"]},
    {"id":"structure-stu-mid-05","level":"mid","profession":"student","title":"The ten-minute presentation with no spine","scenario":"You have ten minutes to present your research methods project. Your current outline is eleven slides in the order you did the work. The professor grades on whether the class can follow the argument, and last semester you watched classmates lose the room by minute four.","task":"Write the governing idea and the three section headers your talk will hang on.","tips":["One sentence the whole talk proves — write it before any slide.","Three sections, each a claim, not a topic ('Sampling skewed young', not 'Methodology').","If a slide serves no section, it goes."],"focus":["structure","impact"]},
    {"id":"structure-stu-mid-06","level":"mid","profession":"student","title":"The agenda that herds the meeting","scenario":"You're chairing this week's club exec meeting. The topic pile: spring event venue, a $250 reimbursement question, recruiting numbers are down, T-shirt design votes, and whether to co-host with the finance society. Last week's meeting ran ninety minutes and decided nothing.","task":"Write a 5-line agenda that groups the topics, orders them by importance, and puts a time and an owner on each.","tips":["Decisions before discussions; discussions before announcements.","Label each item with the outcome needed: decide, discuss, or FYI.","A time box per item is the chair's best friend."],"focus":["structure","clarity"],"placeholder":"1. DECIDE: Spring venue (10 min, Sam) — 2. DECIDE:"},
    {"id":"structure-stu-mid-07","level":"mid","profession":"student","title":"The cover letter with one claim","scenario":"Your cover letter for a consulting internship is a chronological tour of everything you've done since high school. The reader needs one thing: a reason to interview you, supported. You have good material — case competition finalist, club treasurer, strong analytics coursework — but no architecture.","task":"Write the one-sentence claim of the letter and the three supporting points beneath it.","tips":["The claim answers 'why you' in one line — everything else supports it.","Pick the three strongest supports; cut the rest ruthlessly.","Each support gets one sentence of evidence, not a paragraph of biography."],"focus":["structure","impact"],"placeholder":"Claim: I've already done the core of this job — structured problems, owned numbers, presented under pressure."},
    {"id":"structure-stu-mid-08","level":"mid","profession":"student","title":"The STAR answer that actually lands","scenario":"Interviewers keep asking 'tell me about a time you dealt with conflict,' and your answer about your group project meanders — you describe the drama vividly but never clearly say what you did or what came of it.","task":"Script a 4-5 sentence answer with explicit Situation, Task, Action, Result — one sentence-ish each.","tips":["Situation and Task in one or two sentences maximum — the setup is not the story.","Action is the longest part: what you specifically did.","End on the result with something measurable or confirmable."],"focus":["structure","precision"]},
    {"id":"structure-stu-mid-09","level":"mid","profession":"student","title":"Twelve topics, one study guide","scenario":"Your study group asked you to organize the final-exam review for your physiology course. The syllabus lists twelve topics in lecture order. Studying them as a flat list is how everyone failed the midterm — the connections are what the exam tests.","task":"Group the twelve topics into 3-4 themed clusters and write a one-line label for each cluster.","tips":["Group by underlying mechanism or question, not by week number.","A good label teaches: 'Systems that regulate pressure' beats 'Unit 3.'","The grouping IS the studying — structure reveals what's related."],"focus":["structure","clarity"]},
    {"id":"structure-stu-mid-10","level":"mid","profession":"student","title":"The lab report discussion that lists everything","scenario":"Your chemistry lab report's discussion section is currently a chronological narrative of what happened at the bench, including the spill. The rubric wants: what you found, whether it matches theory, and what explains the deviation.","task":"Write a 3-sentence discussion skeleton: finding, comparison to expected, best explanation for the gap.","tips":["One sentence per job — finding, expected-vs-actual, explanation.","The spill belongs in error analysis only if it explains the deviation.","Structure by the rubric's questions, not by your afternoon."],"focus":["structure","precision"],"placeholder":"Our measured yield was 62%, against a theoretical 89%. The gap is most consistent with"},
    {"id":"structure-stu-mid-11","level":"mid","profession":"student","title":"Who does what by when","scenario":"Your four-person group just divided up the final project in a chaotic meeting. You volunteered to send the summary. Your notes are a soup of names, tasks, and half-decided dates. If the message is vague, the last week will be a scramble — again.","task":"Write the group message organized by person, with each person's tasks and dates on one line.","tips":["Structure by person, not by task — people scan for their own name.","Every line: name, deliverable, date. No orphan tasks.","End with the single next checkpoint for everyone."],"focus":["structure","clarity"]},
    {"id":"structure-stu-mid-12","level":"mid","profession":"student","title":"The scholarship essay with three legs","scenario":"The scholarship prompt asks how you've shown leadership. You have material: reviving a dying club, training new tutors at your campus job, and organizing a food drive. Your draft mentions all three in one undifferentiated stream and none of them stick.","task":"Write the essay's governing idea and the three-part structure that carries it.","tips":["Find the thread: what do your three examples prove about you as a leader?","One governing sentence, then one paragraph per example.","Order for effect: strongest example last."],"focus":["structure","impact"],"placeholder":"Governing idea: my leadership pattern is taking things that are quietly failing and rebuilding them —"},
    {"id":"structure-stu-mid-13","level":"mid","profession":"student","title":"SCQA for the event pitch","scenario":"You want the exec board to approve a first-ever alumni networking night. Your draft pitch starts with logistics — date, room, catering. The board hasn't yet heard why this event should exist, so the logistics land on deaf ears.","task":"Write a 4-sentence pitch using SCQA: situation, complication, question, answer.","tips":["Situation: members want career connections — that's why they joined.","Complication: we offer none; seniors leave and we lose the network.","Your answer is the event; logistics come after the board wants it."],"focus":["structure","impact"]},
    {"id":"structure-stu-mid-14","level":"mid","profession":"student","title":"Two readings, one comparison","scenario":"Your discussion post must compare this week's two readings on urban inequality. Your draft summarizes reading A for a paragraph, then reading B for a paragraph, and ends with 'both make good points.' The professor's comment last week: 'Where's the comparison?'","task":"Write a 3-4 sentence post structured around one axis of comparison instead of two summaries.","tips":["Pick the one dimension where they genuinely disagree.","Structure: the axis, A's position, B's position, your verdict.","A-then-B summaries hide the comparison; interleave by idea."],"focus":["structure","clarity"]},
    {"id":"structure-stu-mid-15","level":"mid","profession":"student","title":"Minutes that people can act on","scenario":"You took notes at the club meeting and they're a transcript of who said what for forty minutes. Members won't read that. What they need: what was decided, who owes what, and what's still open.","task":"Rewrite the notes as three labeled sections — Decisions, Action items, Open questions — with 1-2 lines each.","tips":["Decisions are facts now; write them as facts.","Action items need a name and a date or they're wishes.","If a discussion resolved nothing, it's an open question — one line."],"focus":["structure","concision"],"placeholder":"DECIDED: Spring formal moves to April 18, Riverside Hall. ACTION:"},
    {"id":"structure-stu-mid-16","level":"mid","profession":"student","title":"Fifteen minutes with your advisor","scenario":"Your advising appointment is fifteen minutes and you have a tangle of concerns: a major declaration form, whether to take stats or calc next term, a question about the internship credit policy, and vague anxiety about graduating on time. Last time you left with nothing resolved.","task":"Write the ordered list of items you'd open the meeting with, most important first, with the decision each needs.","tips":["Lead with what only the advisor can do — the signature, the policy answer.","Turn vague anxiety into a specific question: 'Am I on track to graduate in four years?'","Announce the list at the start so the advisor helps you manage the clock."],"focus":["structure","clarity"]},
    {"id":"structure-stu-mid-17","level":"mid","profession":"student","title":"The Q&A you can predict","scenario":"Your capstone presentation has a five-minute Q&A. From class feedback you can predict the attacks: sample size, why you excluded part-time students, whether the effect is just selection bias, and two or three lecture-specific method questions. You're preparing answers as one long worried list.","task":"Group the likely questions into 2-3 themes and write the one-sentence core answer for each theme.","tips":["Theme the questions — most are variants of two or three doubts.","One rehearsed core answer per theme flexes to fit variants.","Naming the theme aloud ('That's a sampling question — here's the short answer') buys composure."],"focus":["structure","clarity"]},
    {"id":"structure-stu-mid-18","level":"mid","profession":"student","title":"Peer feedback with a spine","scenario":"You owe written feedback on a classmate's 12-page draft. Your notes are twenty scattered comments of wildly mixed importance — a comma splice sits next to 'the thesis changes in section 3.' Delivered flat, she'll fix the commas and miss the thesis.","task":"Write the feedback's opening structure: overall verdict, the one big issue, then where the small stuff lives.","tips":["Open with the honest overall read in one sentence.","Elevate the single most important problem; subordinate everything else.","Sort the rest into 'worth a pass' and 'take or leave' — hierarchy is kindness."],"focus":["structure","impact"]},
    {"id":"structure-stu-mid-19","level":"mid","profession":"student","title":"The housing complaint that gets a reply","scenario":"Your dorm room has had no heat for six days. You've reported it twice through the app with no response, and it's 12 degrees Celsius in your room at night. Your draft email to the housing office is an angry paragraph that mixes the history, the misery, and the demand.","task":"Write a 4-sentence email structured as issue, evidence, impact, specific request.","tips":["One job per sentence: what's wrong, proof, why it matters, what you want by when.","Dates and ticket numbers are your evidence — deploy them in order.","A structured complaint reads as credible; a vent reads as skippable."],"focus":["structure","precision"],"placeholder":"Room 314's heating has been out since November 2 — tickets #4471 and #4519, both unanswered."},
    {"id":"structure-stu-mid-20","level":"mid","profession":"student","title":"The rebuttal in the moment","scenario":"In your ethics seminar, a classmate just argued that your position on data privacy 'ignores how consent actually works online.' Heads turn to you. You have a real counter, but under pressure you tend to spray three half-arguments instead of landing one.","task":"Script a 3-sentence spoken rebuttal using PREP: point, reason with example, point.","tips":["Concede what's true in their point in half a sentence — it buys the room.","Then one counter-argument, fully built, with one example.","Three half-points lose to one whole point every time."],"focus":["structure","impact"],"placeholder":"You're right that consent online is thin — but that's my argument, not against it:"},
    {"id":"structure-stu-mid-21","level":"mid","profession":"student","title":"Eighty survey answers, one report section","scenario":"Your club surveyed members about why attendance dropped, and you have eighty free-text answers. You're writing the findings section for the exec board. Right now your draft quotes fifteen responses in a row with no organizing frame.","task":"Write the 2-3 sentence findings opener that names the 2-3 groups the answers fall into, with rough counts.","tips":["Read for clusters first: time conflicts, content complaints, social factors.","Lead with the frame ('Three patterns, one dominant'), then the numbers.","Quotes illustrate a cluster; they don't replace the counting."],"focus":["structure","precision"]},
    {"id":"structure-stu-mid-22","level":"mid","profession":"student","title":"The petition to the committee","scenario":"You're petitioning the academic standards committee to let a community-college statistics course count toward your major after a transfer mix-up. The committee reads dozens of petitions and approves the ones that make their decision easy.","task":"Write the petition's first paragraph (3-4 sentences) using SCQA to frame the request.","tips":["Situation and complication in two tight sentences — the mix-up, not your biography.","The question is the committee's decision; state it plainly.","Your answer includes the evidence tag: syllabus attached, equivalent topics listed."],"focus":["structure","clarity"]},
    {"id":"structure-stu-mid-23","level":"mid","profession":"student","title":"The internship-hunt update to your mentor","scenario":"Your mentor asked how the internship search is going. The honest answer is a mess of fragments: eleven applications, two rejections, one interview Friday, a referral you haven't used, and paralysis about a cover letter. Sent as-is, it's unanswerable.","task":"Write a 3-4 sentence update structured as: headline status, what's working, where you need help.","tips":["Roll the fragments up into one status sentence first.","Group the details under 'progressing' and 'stuck.'","End with the one specific thing your mentor could do."],"focus":["structure","clarity"],"placeholder":"Net status: 11 applications out, one interview this Friday, and one bottleneck I could use your eyes on."},
    {"id":"structure-stu-mid-24","level":"mid","profession":"student","title":"From brainstorm soup to proposal","scenario":"Your project team brainstormed for an hour and the whiteboard photo shows thirty sticky notes: app ideas, data sources, worries, half-slogans. You promised to turn it into a one-page proposal by tomorrow. The professor wants: what you'll build, why it matters, how you'll evaluate it.","task":"Write the proposal's three section headers and the single governing sentence above them.","tips":["The professor's three questions are your three sections — adopt them.","The governing sentence is the whole project in one line.","Sticky notes that fit no section were brainstorm exhaust; let them go."],"focus":["structure","concision"]},
    {"id":"structure-stu-mid-25","level":"mid","profession":"student","title":"The one-page handout","scenario":"Your presentation comes with a one-page handout the class keeps after you sit down. Your draft crams in everything you're afraid to leave out — dense paragraphs, no headings, font shrinking to fit. Nobody will reread it, which defeats its purpose.","task":"Design the handout's structure in words: title claim, 3 sections with headers, and what gets cut.","tips":["The handout's job is recall, not completeness.","Headers should be claims someone can re-learn from at a glance.","Whatever you cut still exists — in your talk, in your references."],"focus":["structure","concision"]}
  ],
  "cut-to-the-bone": [
    {"id":"concise-stu-mid-01","level":"mid","profession":"student","title":"The six-sentence email with one sentence of content","scenario":"Your draft to your professor: 'I hope this email finds you well. My name is Jordan Lee and I am in your Tuesday section. I was wondering if it might be possible to ask a question about the essay. I know you are very busy. My question is about the due date. Is the essay due at midnight or at the start of class?'","task":"Rewrite it in two sentences without losing politeness.","tips":["One line of identification, one line of question.","'I was wondering if it might be possible' is eleven words for 'may I.'","Respect for a busy reader is brevity, not apology."],"focus":["concision","clarity"],"placeholder":"Quick question from your Tuesday section: is the essay due at midnight or at the start of class?"},
    {"id":"concise-stu-mid-02","level":"mid","profession":"student","title":"The discussion post wrapped in armor","scenario":"Your post begins: 'I might be totally off base here, and I'm sure others understand this better than I do, but I sort of felt like the author's argument was maybe a little inconsistent in places, though I could be wrong.' Underneath the padding is a good point.","task":"Rewrite the sentence with the hedges cut and the claim standing on its own.","tips":["One 'I think' is honest; five hedges are camouflage.","State the claim, then prove it — the proof is your protection.","Preemptive self-criticism invites readers to agree with it."],"focus":["concision","impact"]},
    {"id":"concise-stu-mid-03","level":"mid","profession":"student","title":"The personal statement 80 words over","scenario":"The application says 500 words maximum. You're at 580, and every sentence feels essential. Three sentences describe your childhood curiosity in different ways, and your opening paragraph takes four sentences to arrive at your subject.","task":"State your cutting plan in 2-3 sentences: what categories go first and why.","tips":["Duplicate ideas go first — keep the best version of each.","Warm-up sentences before the real opening are always cuttable.","Cut whole sentences before trimming words; it reads cleaner."],"focus":["concision","structure"],"placeholder":"First cut: two of the three childhood-curiosity sentences, keeping only the porch-telescope one —"},
    {"id":"concise-stu-mid-04","level":"mid","profession":"student","title":"The presentation script full of packing foam","scenario":"You recorded your practice run. Transcribed, your opening is: 'So basically what we kind of wanted to look at was, um, essentially the question of whether students actually, like, use the gym differently during finals, if that makes sense.' Twelve seconds for one clause.","task":"Rewrite the spoken opening in one clean sentence.","tips":["'Basically,' 'kind of,' 'essentially,' and 'actually' can all die unmourned.","'If that makes sense' surrenders authority — cut it.","A short declarative sentence sounds more confident than fluent filler."],"focus":["concision","impact"],"placeholder":"We asked one question: do students use the gym differently during finals?"},
    {"id":"concise-stu-mid-05","level":"mid","profession":"student","title":"The abstract at double the limit","scenario":"The undergraduate research symposium wants a 150-word abstract. Yours is 290. It describes the motivation twice, lists all five statistical tests by name, and spends forty words on future directions the poster doesn't cover.","task":"Write the 2-3 sentence core the abstract must keep: question, method in a phrase, main finding.","tips":["An abstract earns each word: question, approach, result, significance.","Five tests by name become 'regression analysis' — the poster has details.","Future work is the first cut in any over-limit abstract."],"focus":["concision","precision"]},
    {"id":"concise-stu-mid-06","level":"mid","profession":"student","title":"The essay that announces itself","scenario":"Your draft opens: 'In this essay, I will first discuss the background of the debate, then I will examine both sides, and finally I will offer my own conclusion about which argument is stronger.' Your professor has written 'just do it, don't announce it' on your last two papers.","task":"Replace the announcement with a 1-2 sentence opening that starts the actual argument.","tips":["Meta-commentary describes the essay; an opening should BE the essay.","Start with the debate's sharpest tension or your position.","Signposting has its place — inside long documents, not as a substitute for a thesis."],"focus":["concision","impact"]},
    {"id":"concise-stu-mid-07","level":"mid","profession":"student","title":"The resume bullet with a course's worth of words","scenario":"Your resume bullet reads: 'Was responsible for assisting in the coordination and facilitation of various club events and activities throughout the course of the academic year.' Twenty-two words, zero facts.","task":"Rewrite it as one bullet under twelve words with at least one number.","tips":["'Was responsible for assisting in the coordination of' = 'coordinated.'","'Various' and 'throughout the course of' carry no information.","A number does more work than five adjectives."],"focus":["concision","precision"],"placeholder":"Coordinated 6 club events for 300+ attendees, including"},
    {"id":"concise-stu-mid-08","level":"mid","profession":"student","title":"The group message that buries its ask","scenario":"Your message to the group chat runs nine sentences: how your week went, two apologies, a recap of the last meeting, and — in sentence eight — the actual point: you need everyone's slides by Thursday night to merge the deck.","task":"Cut it to two sentences that keep the ask and the deadline.","tips":["Find the one sentence that matters; everything else auditions for deletion.","In group chats, long messages get skimmed and asks get missed.","The deadline goes in the same sentence as the ask."],"focus":["concision","clarity"]},
    {"id":"concise-stu-mid-09","level":"mid","profession":"student","title":"Redundant pairs and doubled words","scenario":"Your history essay is padded with pairs: 'each and every soldier,' 'first and foremost,' 'the end result,' 'completely and totally destroyed,' 'past history.' Your professor circles them; you keep writing them because they feel emphatic.","task":"Rewrite this sentence cutting every redundancy: 'First and foremost, the end result of the campaign was that each and every supply line was completely and totally destroyed.'","tips":["In each pair, one word is doing all the work — keep that one.","'End result,' 'past history,' 'final outcome': the first word is free.","Emphasis comes from precision, not duplication."],"focus":["concision","precision"],"placeholder":"The campaign destroyed every supply line."},
    {"id":"concise-stu-mid-10","level":"mid","profession":"student","title":"The cover letter that clears its throat","scenario":"Your cover letter opens: 'I am writing to express my sincere interest in applying for the position of Marketing Intern as advertised on your company's website, which I discovered while searching for opportunities in the field of marketing.' The reader learned nothing they didn't know.","task":"Write a replacement opening sentence that carries actual information about you.","tips":["They know what job it is and where it was posted — skip both.","Open with your strongest relevant fact.","Every sentence a recruiter reads is a gift of seconds; spend it on substance."],"focus":["concision","impact"],"placeholder":"I've spent two years running social accounts that grew from 200 to 4,000 followers —"},
    {"id":"concise-stu-mid-11","level":"mid","profession":"student","title":"Thirty seconds of office-hours queue","scenario":"The line behind you is six students deep and the professor is visibly pacing the clock. You need to ask about your paper topic. Your rehearsed version includes the three topics you rejected and why, before the one you actually want approved.","task":"Script your ask in two spoken sentences.","tips":["Lead with the topic you want; the rejected ones only if asked.","One sentence of topic, one sentence of the specific worry.","Queue courtesy is concision."],"focus":["concision","clarity"]},
    {"id":"concise-stu-mid-12","level":"mid","profession":"student","title":"The thank-you note that overstays","scenario":"After your internship interview, your thank-you email draft is twelve sentences: gratitude expressed three ways, a re-argument of your whole candidacy, and two new facts you forgot to mention live. Long thank-yous read as anxious.","task":"Cut it to 3 sentences: thanks, one specific moment from the conversation, forward-looking close.","tips":["One expression of thanks — the second and third dilute the first.","Reference one specific exchange to prove you were present.","Do not re-run the interview; the note's job is warmth and recall."],"focus":["concision","audience"]},
    {"id":"concise-stu-mid-13","level":"mid","profession":"student","title":"Nominalizations in the lab report","scenario":"Your methods section reads: 'The performance of the titration was conducted after the completion of the calibration of the pH meter, and the collection of measurements was undertaken at intervals.' Verbs entombed in nouns.","task":"Rewrite the sentence with the actions as verbs.","tips":["'The performance of the titration was conducted' = 'we titrated.'","Hunt the '-tion of' pattern; a live verb is hiding inside each one.","Verb-driven sentences are shorter and read as more competent."],"focus":["concision","clarity"],"placeholder":"After calibrating the pH meter, we titrated and recorded measurements every"},
    {"id":"concise-stu-mid-14","level":"mid","profession":"student","title":"The apology tax on every question","scenario":"Your emails to professors carry a tax: 'Sorry to bother you,' 'I know this is probably a dumb question,' 'Apologies if this was covered in class.' One draft has three apologies and one question. You're not sorry; you're a student asking a course question — the job description.","task":"Rewrite this email in two sentences with zero apologies: 'Sorry to bother you! I know you're busy and this might be a dumb question, but I wasn't sure if the problem set needed us to show work. Sorry if you already said this!'","tips":["Course questions are the professor's job, not an imposition.","'Might be a dumb question' primes the reader to agree.","Politeness lives in tone and brevity, not in self-diminishment."],"focus":["concision","impact"],"placeholder":"Should we show full work on the problem set, or are final answers enough?"},
    {"id":"concise-stu-mid-15","level":"mid","profession":"student","title":"The career-fair introduction, timed","scenario":"The line at the Deloitte booth gives you maybe fifteen seconds of the recruiter's attention before they glance at the next student. Your current intro covers your major, minor, hometown, club memberships, and course load. They retain none of it.","task":"Write a two-sentence introduction: who you are and the one thing you want them to remember.","tips":["Pick your single most relevant fact and lead with it.","The goal is one memorable hook, not full coverage.","End with a question or ask — it converts the intro into a conversation."],"focus":["concision","impact"],"placeholder":"I'm a third-year economics major who just won our case competition — I'd love to ask about your summer analyst program."},
    {"id":"concise-stu-mid-16","level":"mid","profession":"student","title":"The recruitment blurb with a hard cap","scenario":"The student activities newsletter gives your club exactly 40 words. Your draft is 85: club history, meeting times, past events, three exclamation points, and the actual pitch somewhere in the middle.","task":"Write the 40-word-max blurb.","tips":["One hook, one concrete detail, one call to action — that's 40 words.","History is for the website, not the blurb.","Read it as a bored scroller: what stops the thumb?"],"focus":["concision","audience"]},
    {"id":"concise-stu-mid-17","level":"mid","profession":"student","title":"The over-qualified claim","scenario":"Your lab report conclusion reads: 'It could potentially be suggested that the data may possibly indicate a somewhat significant trend that might be consistent with the hypothesis.' Six qualifiers guarding one finding. Your TA's margin note: 'Do you believe your own data?'","task":"Rewrite the sentence with at most one honest qualifier.","tips":["Choose the one qualifier that reflects your real uncertainty; delete the bodyguards.","'Could potentially possibly maybe' is not rigor — error bars are rigor.","Say what the data shows, then state its limits in a separate sentence."],"focus":["concision","precision"],"placeholder":"The data shows a positive trend consistent with the hypothesis, though"},
    {"id":"concise-stu-mid-18","level":"mid","profession":"student","title":"The event email nobody finishes","scenario":"Your club's event announcement is 300 words: a welcome paragraph, the club's mission, the event, a speaker bio, parking information, and a sign-off quoting Gandhi. Open rates are fine; RSVPs are terrible. People stop reading before the sign-up link.","task":"Cut it to under 100 words while keeping event, time, place, reason to come, and the link placement.","tips":["The RSVP link goes high, not after the bio.","Mission statements belong on the website, not in event emails.","One reason to come, vividly put, beats five listed."],"focus":["concision","impact"]},
    {"id":"concise-stu-mid-19","level":"mid","profession":"student","title":"The two-minute answer to a thirty-second question","scenario":"Mock-interview feedback said your answers average two minutes. The question 'Why this company?' got: your career philosophy, a childhood anecdote, a summary of their website, and finally two genuine reasons. The interviewer had stopped writing.","task":"Script the 30-second version: your two genuine reasons, one sentence each, plus an opener and close.","tips":["Two reasons, stated then supported, beat four reasons listed.","Cut the runway — the first sentence should already contain a reason.","Practice against a timer; 30 seconds is roughly 75 words."],"focus":["concision","structure"]},
    {"id":"concise-stu-mid-20","level":"mid","profession":"student","title":"Three paragraphs to three bullets","scenario":"You wrote your project group three paragraphs explaining the new file organization in the shared drive. It's all necessary information — where drafts go, where final versions go, the naming convention — but nobody will read three paragraphs about folders.","task":"Convert the message to three bullets of one line each.","tips":["Each bullet: one rule, imperatively stated.","Cut every 'the reason for this is' — rules can stand without defense.","If a rule needs a paragraph, it's two rules."],"focus":["concision","clarity"],"placeholder":"• Drafts → /Working. • Finals → /Submit, named"},
    {"id":"concise-stu-mid-21","level":"mid","profession":"student","title":"The caption that must fit","scenario":"You run the club's Instagram. The event graphic is done; your caption draft is four sentences of context that repeats everything already on the graphic — date, time, location — plus hashtags. Captions get one line before the fold.","task":"Write the one-line caption that adds something the graphic doesn't say.","tips":["Never caption what the image already states.","Add the one thing a graphic can't: voice, urgency, or a reason.","Front-load — the fold cuts you at roughly ten words."],"focus":["concision","impact"]},
    {"id":"concise-stu-mid-22","level":"mid","profession":"student","title":"'I think' as sentence filler","scenario":"A paragraph of your persuasive essay contains 'I think' four times, 'I feel like' twice, and 'in my opinion' once — in an essay with your name on it, where every claim is already understood to be yours.","task":"Rewrite this sentence without the ownership disclaimers: 'I think the policy failed because, in my opinion, the incentives were misaligned, and I feel like the data supports this.'","tips":["The byline already says it's your opinion — the disclaimer is rent you don't owe.","Keep 'I think' only where you're genuinely marking uncertainty against fact.","Watch what remains: a claim, a mechanism, and evidence — stronger naked."],"focus":["concision","impact"],"placeholder":"The policy failed because the incentives were misaligned; the enrollment data shows"},
    {"id":"concise-stu-mid-23","level":"mid","profession":"student","title":"The subject line that says nothing","scenario":"You're emailing your professor about missing Friday's midterm review due to a varsity match, with a question about the makeup materials. Your subject line: 'Question.' Professors triage by subject line, and 'Question' goes to the bottom of the pile.","task":"Write a subject line under ten words that carries the message's core.","tips":["Subject = topic + what you need: 'Missing Fri review (varsity) — makeup materials?'","Assume the body may not be read today; the subject should survive alone.","Under ten words, no 'Hello' and no mystery."],"focus":["concision","clarity"]},
    {"id":"concise-stu-mid-24","level":"mid","profession":"student","title":"The extension request drowning in backstory","scenario":"Your extension request email is 250 words, of which 200 narrate your week: the double shift, the flooded apartment, the dead laptop, the roommate crisis. The professor needs three facts: what you're asking, until when, and one credible reason.","task":"Cut the request to three sentences.","tips":["Pick the single strongest reason; three reasons read as excuses.","Ask, date, reason — then stop.","The professor decides in ten seconds either way; length only costs goodwill."],"focus":["concision","clarity"]},
    {"id":"concise-stu-mid-25","level":"mid","profession":"student","title":"The LinkedIn summary written like an essay","scenario":"Your LinkedIn 'About' section is a five-paragraph essay: childhood inspiration, high school achievements, course-by-course journey, philosophy of learning, and career dreams. Recruiters read the first two lines before deciding to click 'see more.'","task":"Write a 3-sentence summary where the first line earns the click.","tips":["Line one: what you are and your sharpest proof point.","Present tense, concrete nouns, one number if you have one.","The 'see more' fold is your real word limit — write for it."],"focus":["concision","audience"],"placeholder":"Third-year statistics major who turned a class project into a tool 400 students use for course planning."}
  ],
  "precision-and-evidence": [
    {"id":"precision-stu-mid-01","level":"mid","profession":"student","title":"'A lot of people came'","scenario":"Your end-of-semester club report to the student activities office says the fall speaker series was 'very well attended and a huge success.' You have the sign-in sheets: 68, 54, and 81 attendees, up from around 30 per event last year. Funding decisions ride on this report.","task":"Rewrite the sentence with the numbers doing the work.","tips":["'Well attended' is a claim; 68, 54, and 81 are facts.","The comparison to last year is the real story — include the baseline.","Funders can defend numbers to their own bosses; they can't defend 'huge success.'"],"focus":["precision","impact"],"placeholder":"The fall series drew 68, 54, and 81 attendees — more than double last year's average of 30."},
    {"id":"precision-stu-mid-02","level":"mid","profession":"student","title":"The grade appeal built on effort","scenario":"You're meeting your professor about a C+ on your term paper. Your planned argument is 'I worked really hard on this and spent way more time than on my other papers.' Effort isn't on the rubric. What you actually have: the rubric says thesis clarity was the main deduction, but your thesis is stated on page one and defended in every section.","task":"Write the 2-3 sentence case you'd make, grounded in the rubric instead of effort.","tips":["Argue from the rubric's own categories — that's the shared standard.","Point to specific pages and sentences, not overall impressions.","Effort claims can't be verified; text on the page can."],"focus":["precision","structure"]},
    {"id":"precision-stu-mid-03","level":"mid","profession":"student","title":"The unquantified resume","scenario":"Your resume bullet says 'Helped grow the club's social media presence significantly.' You know the real numbers: you ran the account for 14 months, posted three times a week, and followers went from 210 to 1,450. Recruiters discount every claim that lacks a number.","task":"Rewrite the bullet with the numbers in it.","tips":["'Significantly' is what you write when you haven't looked up the number.","Growth needs both endpoints: from 210 to 1,450 beats '+590%'... but include the percent if it's striking.","Time frame matters — 14 months makes the growth interpretable."],"focus":["precision","impact"],"placeholder":"Grew club Instagram from 210 to 1,450 followers in 14 months, posting 3x weekly."},
    {"id":"precision-stu-mid-04","level":"mid","profession":"student","title":"Eighty responses, one insight","scenario":"Your member survey came back: 62% cite Thursday scheduling conflicts, 20% say meetings run too long, and the free-text answers repeatedly mention that new members feel ignored. The exec board asked you 'what did the survey say?' A data dump isn't an answer.","task":"Write the one-sentence insight you'd lead with, then one sentence on what it implies.","tips":["An insight ranks the findings: which one explains the attendance drop?","'62% cite Thursday conflicts' is a finding; 'we're losing members to a scheduling problem we can fix' is an insight.","Save the full breakdown for the appendix or the follow-up question."],"focus":["precision","clarity"]},
    {"id":"precision-stu-mid-05","level":"mid","profession":"student","title":"What, so what, now what at the bench","scenario":"Your PI asked for a summary of this week's runs. You have it: the new primer set amplified cleanly in 9 of 10 samples, versus 4 of 10 with the old set. You tend to report the What and stop, leaving your PI to extract the meaning and next step themselves.","task":"Write a 3-sentence update: what happened, what it means, what you propose next.","tips":["What: the numbers. So what: the old primers were the bottleneck. Now what: your proposed next run.","Each sentence has one distinct job — don't blend them.","Proposing the next step is what turns a report into a contribution."],"focus":["precision","structure"],"placeholder":"The new primers amplified 9/10 samples versus 4/10 with the old set."},
    {"id":"precision-stu-mid-06","level":"mid","profession":"student","title":"The vague extension request","scenario":"Your draft to your professor says you need 'a bit more time' because the project is 'mostly done but not quite there.' The professor can't evaluate that. The truth is specific: analysis complete, four of six pages written, and you need until Monday 9am.","task":"Rewrite the request in 2-3 sentences with the specifics.","tips":["'Mostly done' means nothing; 'analysis complete, 4 of 6 pages drafted' is a status.","Propose an exact deadline — date and time — not 'a bit more time.'","Specific requests signal control; vague ones signal drowning."],"focus":["precision","clarity"]},
    {"id":"precision-stu-mid-07","level":"mid","profession":"student","title":"'Leadership experience' with no leader in sight","scenario":"Your scholarship application says you 'demonstrated strong leadership skills through various campus involvements.' The reviewers have read that exact sentence four hundred times. What you actually did: took over a 12-member club at risk of losing recognition, recruited 23 new members, and ran its first funded event.","task":"Rewrite the sentence with the concrete record instead of the abstraction.","tips":["'Leadership' is a conclusion — give the evidence and let reviewers conclude it.","Numbers and stakes: 12 members, risk of derecognition, 23 recruits.","One vivid specific beats three vague involvements."],"focus":["precision","impact"],"placeholder":"When our 12-member club was one semester from losing university recognition, I"},
    {"id":"precision-stu-mid-08","level":"mid","profession":"student","title":"'Significantly improved' under questioning","scenario":"In interviews you say your tutoring 'significantly improved my students' grades.' One interviewer asked, 'How do you know?' and you froze. You do know: you tutored six students weekly for a semester, and five raised their course grade by at least one letter.","task":"Script the 1-2 sentence answer with the evidence built in.","tips":["Carry the number with the claim so the follow-up never lands.","Scope honestly: five of six, one semester — precision includes limits.","If you can't quantify, qualify concretely: name what changed and how you saw it."],"focus":["precision","impact"]},
    {"id":"precision-stu-mid-09","level":"mid","profession":"student","title":"The claim your groupmate will get asked about","scenario":"Your group's slide says 'studies show remote learning hurts student outcomes.' You wrote it from memory of something you read. Your teammate presents that slide, and your professor is known for asking 'which studies?' Either find the citation or fix the claim.","task":"Rewrite the slide's claim so it passes the skeptic test — cited or honestly scoped.","tips":["Every 'studies show' needs a name, year, and finding — or softer wording.","A precise narrow claim ('one 2021 study of 8th graders found...') survives; a broad vague one dies.","Never hand a teammate a claim you can't back."],"focus":["precision","structure"]},
    {"id":"precision-stu-mid-10","level":"mid","profession":"student","title":"The budget that's actually a guess","scenario":"Your funding request says the club trip will cost 'around $1,200 for travel and other expenses.' The committee tables imprecise requests. You have the real figures: van rental $410, fuel estimate $95, registration $150 x 4 members, lodging $180.","task":"Rewrite the request line with an itemized total.","tips":["Itemized requests get approved; 'and other expenses' gets questions.","Show the arithmetic: 410 + 95 + 600 + 180 = $1,285 — ask for the real number.","Label estimates as estimates ('fuel, est. $95') — that's precision too."],"focus":["precision","clarity"],"placeholder":"Total request: $1,285 — van rental $410, fuel (est.) $95, registration $150 × 4, lodging $180."},
    {"id":"precision-stu-mid-11","level":"mid","profession":"student","title":"'The reading says' — where?","scenario":"In seminar you claimed 'the reading basically argues that institutions matter more than culture,' and the professor asked, 'Where does she say that?' You flailed. You know the move now: claims about a text need a page, a passage, or an honest 'my inference from.'","task":"Script a 2-sentence seminar claim that anchors itself to a specific passage.","tips":["'On page 43 she argues...' is armor — bring page numbers to seminar.","Distinguish quoting, paraphrasing, and inferring — and say which you're doing.","If you can't locate it, downgrade the claim before someone does it for you."],"focus":["precision","clarity"],"placeholder":"On page 43, she argues institutions 'outlive the cultures that build them' — which I read as"},
    {"id":"precision-stu-mid-12","level":"mid","profession":"student","title":"The grading-error email","scenario":"Your problem set came back with 31/40, but the sub-scores on the page sum to 35. Your draft email says 'I think there's something wrong with my grade.' The TA processes ninety of these; vague claims go to the bottom of the pile.","task":"Write a 2-sentence email with the exact arithmetic.","tips":["Name the assignment, the printed sub-scores, their sum, and the recorded total.","Make checking take ten seconds — that's what gets fast fixes.","Factual tone: it's arithmetic, not an accusation."],"focus":["precision","concision"],"placeholder":"PS4 sub-scores (8+9+10+8) sum to 35, but the recorded total is 31 — could you re-check?"},
    {"id":"precision-stu-mid-13","level":"mid","profession":"student","title":"The event recap that earns next year's budget","scenario":"Your recap of the career-panel event says it 'went great and got amazing feedback.' The numbers you're sitting on: 74 attendees against 60 chairs, 31 sign-ups for the mentorship follow-up, cost $340, and a 4.6/5 average on the feedback form.","task":"Write a 2-3 sentence recap that turns those numbers into the case for repeating the event.","tips":["Pick the numbers that argue: over capacity, $4.60 per attendee, 42% conversion to sign-ups.","'Amazing feedback' is decoration; '4.6/5 from 52 responses' is evidence.","End with the number that makes next year's ask obvious."],"focus":["precision","impact"]},
    {"id":"precision-stu-mid-14","level":"mid","profession":"student","title":"'Immersed in the culture'","scenario":"Your study-abroad reflection essay says you were 'fully immersed in the local culture and grew so much as a person.' The committee reading it for a returning-student award has no idea what you actually did. The truth is concrete: you lived with a host family, took two courses taught in Spanish, and volunteered weekly at a neighborhood tutoring center.","task":"Rewrite the sentence with the specifics carrying the claim.","tips":["'Immersed' and 'grew' are conclusions — show the evidence instead.","Specifics prove themselves: courses in Spanish, weekly volunteering, a host family.","One concrete scene outweighs a paragraph of abstractions."],"focus":["precision","impact"],"placeholder":"I lived with a host family in Valparaíso, took two courses taught entirely in Spanish, and"},
    {"id":"precision-stu-mid-15","level":"mid","profession":"student","title":"The poll that says less than you want it to","scenario":"You polled the club Discord about moving meetings online: 11 voted yes, 4 no. You're about to tell the exec board 'members overwhelmingly want to go online.' The club has 63 members; 15 voted, and Discord skews toward the members who already skip in-person events.","task":"Write the 1-2 sentence honest summary of what the poll supports.","tips":["Report the denominator: 11 of 15 voters, from 63 members.","Name the bias if you can see it — the board will find it anyway.","An honestly-scoped finding still argues; an oversold one gets discarded whole."],"focus":["precision","clarity"]},
    {"id":"precision-stu-mid-16","level":"mid","profession":"student","title":"The 'soon' that means nothing","scenario":"Your project group asked when your data-cleaning script will be ready. You typed 'soon, almost done!' Last time you said that, it meant three days, a teammate built on a stale file, and merging was a nightmare. The honest answer: two known bugs left, done tomorrow by 6pm.","task":"Rewrite the reply with a real time and a real state.","tips":["'Soon' pushes your uncertainty onto everyone else's planning.","State + deadline: 'two bugs left, done by 6pm tomorrow.'","If the estimate is soft, give the range and when you'll firm it up."],"focus":["precision","clarity"],"placeholder":"Two known bugs left — I'll have it merged by 6pm tomorrow."},
    {"id":"precision-stu-mid-17","level":"mid","profession":"student","title":"The statistic you half-remember","scenario":"Your presentation draft claims '90% of communication is body language.' You've heard it everywhere; you have no source. Ten minutes of checking reveals the real study says something much narrower, and the 90% figure is a decades-old misreading. Your professor eats unsourced statistics alive.","task":"Write the corrected 1-2 sentence version of the claim, scoped to what the evidence supports.","tips":["A famous number with no source is a liability, not a fact.","Narrow the claim to what the actual study found — narrower and true beats broad and false.","'Often cited as X, though the original study only showed Y' can itself be a strong move."],"focus":["precision","structure"]},
    {"id":"precision-stu-mid-18","level":"mid","profession":"student","title":"'Passionate about marketing'","scenario":"Your cover letter says you are 'deeply passionate about marketing and always have been.' Every applicant says this; none of them prove it. Your actual record: you run a food-review Instagram with 2,000 followers, A/B tested caption styles for a month, and took the only two marketing courses your college offers.","task":"Rewrite the sentence so the evidence replaces the adjective.","tips":["Passion is demonstrated by what you do unprompted — lead with that.","'I A/B tested my own captions for a month' proves more than any adjective.","Cut 'always have been' — unverifiable and generic."],"focus":["precision","impact"]},
    {"id":"precision-stu-mid-19","level":"mid","profession":"student","title":"The feedback that can't be acted on","scenario":"Your peer-review comment on a classmate's draft says 'the flow feels off in the middle and some parts are confusing.' She can do nothing with that. You know what you actually stumbled on: paragraph four assumes a definition she gives in paragraph six, and two paragraphs repeat the same point.","task":"Rewrite the feedback as 2 sentences she can act on directly.","tips":["Point to locations: paragraph numbers, sentences, page.","Diagnose, don't just react: 'assumes a term defined later' explains the confusion.","Actionable feedback names the fix or makes it obvious."],"focus":["precision","audience"],"placeholder":"Paragraph 4 uses 'redlining' before you define it in paragraph 6 — either"},
    {"id":"precision-stu-mid-20","level":"mid","profession":"student","title":"What, so what, now what for the attendance drop","scenario":"Club attendance fell from about 25 per meeting in September to 9 last week. You're raising it at the exec meeting. Your instinct is to present the scary numbers and stop — but the board needs the meaning and a proposed move, or the discussion will just be group anxiety.","task":"Write the 3-sentence version: the numbers, your best explanation, your proposed next step.","tips":["What: 25 to 9 since September. So what: it tracks the move to Thursday nights. Now what: your proposal.","Offer your explanation as a hypothesis with its evidence, not a certainty.","Always arrive with a next step — even 'poll members by Friday' counts."],"focus":["precision","structure"]},
    {"id":"precision-stu-mid-21","level":"mid","profession":"student","title":"The project description that hides its scope","scenario":"Your internship application describes your class project as 'a semester-long software project completed as part of a team.' The scope was real: four people, ten weeks, 3,000 lines of Python, 40 user tests, and it's still used by the department. None of that is on the page.","task":"Rewrite the description in 1-2 sentences with the scope made visible.","tips":["Scope markers — team size, duration, scale, users — are what recruiters scan for.","'Still in use by the department' is the strongest line; don't leave it out.","Precision about your own role: which parts were yours?"],"focus":["precision","impact"],"placeholder":"With three teammates, I built a 3,000-line Python scheduling tool over ten weeks — the department still uses it to"},
    {"id":"precision-stu-mid-22","level":"mid","profession":"student","title":"The grad-school question, unarmed","scenario":"You're asking your advisor whether a master's program is realistic for you. Your plan was to open with 'do you think I'm good enough?' — unanswerable. The relevant facts exist: 3.4 GPA overall, 3.7 in-major, one semester of research, no thesis yet, and two specific programs in mind.","task":"Script the 2-3 sentence version of your question with the facts attached.","tips":["Give the advisor the inputs: GPA, in-major GPA, research record, target programs.","Ask a decidable question: 'am I competitive for these two programs?'","Vague questions get reassurance; precise ones get advice."],"focus":["precision","audience"]},
    {"id":"precision-stu-mid-23","level":"mid","profession":"student","title":"Claim versus inference in the discussion post","scenario":"Your draft post says 'the author believes capitalism caused the crisis.' Rereading, the author never says that — she documents the deregulation timeline and lets readers conclude. Your professor grades sharply on the difference between what a text says and what you infer from it.","task":"Rewrite the sentence so the author's claim and your inference are clearly separated.","tips":["'She documents X' and 'I infer Y' are different moves — mark them.","Attribute precisely: says, implies, documents, assumes — each is a different verb for a reason.","Your inference, labeled as yours, is analysis; disguised as hers, it's a misreading."],"focus":["precision","clarity"],"placeholder":"The author documents the deregulation timeline without assigning blame; the causal claim is my inference:"},
    {"id":"precision-stu-mid-24","level":"mid","profession":"student","title":"The table that needs a sentence","scenario":"Your slide shows a table of gym-usage counts by hour for finals week versus a normal week. In practice runs you say 'as you can see, the data shows some interesting patterns.' Nobody sees. The table's actual story: usage shifts three hours later and total visits drop by a quarter.","task":"Write the one sentence you'd say instead, stating the takeaway.","tips":["Never make the audience mine the table — hand them the finding.","One takeaway per table; if there are two, that's two slides.","'As you can see' means you haven't decided what they should see."],"focus":["precision","impact"],"placeholder":"During finals, gym visits shift three hours later and drop 25% overall — students trade workouts for library time."},
    {"id":"precision-stu-mid-25","level":"mid","profession":"student","title":"The skeptic test before you hit send","scenario":"Your op-ed draft for the campus paper claims 'most students can't afford the new meal plan.' A skeptical reader — and the comments section will be full of them — will ask: how many is most, afford by what standard, says who? You have one real data point: the plan costs 22% more and the dining office's own survey found 41% of respondents called it a financial strain.","task":"Rewrite the claim so it survives the skeptic, using what you actually have.","tips":["Run the attack yourself first: how do you know 'most'? You don't — so don't say it.","Anchor to your two real numbers: 22% increase, 41% reporting strain.","Claims sized to their evidence are the ones that change minds."],"focus":["precision","impact"]}
  ],
  "executive-presence": [
    {"id":"presence-stu-mid-01","level":"mid","profession":"student","title":"The menu instead of the meal","scenario":"Your project group can't pick a research topic, and you've become the person who lists options: 'We could do housing, or maybe transit, or food deserts — whatever you all think.' You actually believe housing is the strongest topic, and the group is circling because nobody will commit.","task":"Script a 2-3 sentence statement that recommends housing and owns the recommendation.","tips":["'I recommend housing, because...' — the sentence the group is waiting for.","Give your top two reasons, then invite pushback explicitly.","Presenting a menu feels safe but reads as absence; a recommendation moves the room."],"focus":["impact","clarity"],"placeholder":"I recommend we do housing — the data's public, and it affects everyone in this room."},
    {"id":"presence-stu-mid-02","level":"mid","profession":"student","title":"Killing the event nobody will kill","scenario":"Your club's annual trivia night has lost money and attendance three years running, but it's tradition and the founder still shows up to it. As events chair, you've concluded it should end. At the exec meeting you'll be tempted to float it passively — 'maybe we should think about possibly retiring it?'","task":"Write the 2-3 sentence recommendation you'd deliver, owning the call.","tips":["Recommend, don't float: 'I recommend we retire trivia night this year.'","Bring the two numbers that made the decision for you.","Acknowledge the tradition in one respectful clause — then still land the call."],"focus":["impact","precision"]},
    {"id":"presence-stu-mid-03","level":"mid","profession":"student","title":"'This might be dumb, but...'","scenario":"In seminar you preface every contribution with 'this might be a dumb point' or 'sorry if this is off track.' Your professor privately told you the points are good and the prefaces are hurting you — participation is a third of the grade, and you're discounting yourself before anyone else can.","task":"Take a point you'd normally hedge and script it as 2 sentences with a confident opening.","tips":["Delete the preface entirely; start with the claim.","Confidence is not arrogance — you can assert a reading and still welcome challenge.","If you must signal uncertainty, do it precisely: 'One passage complicates my reading.'"],"focus":["impact","clarity"]},
    {"id":"presence-stu-mid-04","level":"mid","profession":"student","title":"Signposting the ten-minute talk","scenario":"Feedback from your last class presentation: 'hard to follow, felt like one long stream.' The content was fine; the audience just never knew where they were. This time you want the structure audible — announced at the start, marked at every turn.","task":"Write your opening signpost sentence and the three transition sentences you'd use at each section boundary.","tips":["Open with the map: 'Three things: the problem, what we found, what it means.'","Transitions restate progress: 'That's the problem — here's what we found.'","Spoken structure must be louder than written structure; you can't reread a talk."],"focus":["structure","clarity"],"placeholder":"I'll cover three things: why commuter students skip office hours, what our survey found, and one fix the department could ship this term."},
    {"id":"presence-stu-mid-05","level":"mid","profession":"student","title":"Fact versus judgment about a teammate","scenario":"Your professor asks each group member to privately assess how the team is functioning. One teammate has missed both internal deadlines and two of four meetings. You're angry, and your draft says he 'doesn't care about the project and is lazy.' That's a judgment; you have facts.","task":"Write 2 sentences reporting the facts and clearly separating any judgment.","tips":["Facts: missed deadlines and meetings, with dates. Judgments: 'lazy,' 'doesn't care.'","Report facts; if asked for an assessment, label it: 'My read is...'","Fact-based reports get action; character verdicts get discounted as drama."],"focus":["precision","clarity"]},
    {"id":"presence-stu-mid-06","level":"mid","profession":"student","title":"Owning the decision in the interview","scenario":"An interviewer asks about a time you made a tough call. In your group project, you decided to cut the recommendation-engine feature to hit the deadline. Your instinct is to blur it — 'we sort of collectively realized' — because owning it feels like bragging. It was your call, and it was right.","task":"Script a 2-3 sentence answer that owns the decision in the first person.","tips":["'I decided' — singular — where it's true. Interviewers hire people, not committees.","Name what you weighed: the deadline against the feature's value.","Credit the team for execution; own the judgment call."],"focus":["impact","structure"],"placeholder":"With two weeks left and the core still buggy, I made the call to cut our recommendation feature."},
    {"id":"presence-stu-mid-07","level":"mid","profession":"student","title":"Recommend first, dissent after","scenario":"Your study group is choosing a case for the case-competition entry, and you've done the most background work. You know which case plays to the team's strengths. You want to be decisive without steamrolling three people who haven't spoken yet.","task":"Script 2-3 sentences that state your recommendation with reasons, then genuinely open the floor.","tips":["Recommendation first, then 'what am I missing?' — order matters.","Give reasons tied to the team: 'it plays to our finance depth.'","Opening the floor after a clear stance gets better dissent than false neutrality."],"focus":["impact","audience"]},
    {"id":"presence-stu-mid-08","level":"mid","profession":"student","title":"The confident 'within what I know'","scenario":"During your presentation Q&A, a classmate asks a question you can mostly answer — you know the finding, but not the exact figure. Your habit is to collapse: 'um, I'm not sure, I'd have to check everything.' You know more than that, and the room's confidence in your work follows your own.","task":"Script a 2-sentence answer that asserts what you know and bounds what you don't.","tips":["Lead with the part you're sure of, stated plainly.","Bound the gap precisely: 'the exact figure I'd need to check — it's in our appendix.'","Don't let one missing decimal discredit ten solid findings."],"focus":["clarity","impact"],"placeholder":"The direction is clear — usage drops during finals. The exact percentage I'd want to confirm from the appendix rather than misquote."},
    {"id":"presence-stu-mid-09","level":"mid","profession":"student","title":"Arriving with a plan, not a shrug","scenario":"Your advising meeting is about next semester. Your usual approach is to sit down and ask 'what should I take?' — outsourcing the whole decision. You've actually thought about it: you want the research methods course, stats, and one elective, but you're unsure whether methods conflicts with your work schedule.","task":"Script the 2-3 sentence opening that proposes your plan and asks the one real question.","tips":["Propose, then verify: 'Here's my plan — one thing I need your read on.'","Advisors advise better against a concrete plan than a blank page.","Owning your plan is presence; it changes how the meeting treats you."],"focus":["impact","structure"],"placeholder":"My plan for spring is research methods, stats 301, and one elective — the one thing I need your help on is"},
    {"id":"presence-stu-mid-10","level":"mid","profession":"student","title":"Defending the budget line by line","scenario":"As treasurer, you're presenting the spring budget and you cut the merchandise line by half to fund a second speaker event. The merch loyalists will push back. You need to present the change as a decision with visible reasoning, not slip it past them.","task":"Write a 3-sentence signposted defense: the change, the reasoning, the invitation to challenge.","tips":["Name the change plainly first — burying it costs trust when it's found.","Show the reasoning structure: what merch returned per dollar versus events.","Invite the challenge on your terms: 'push back on the numbers if you see it differently.'"],"focus":["structure","impact"]},
    {"id":"presence-stu-mid-11","level":"mid","profession":"student","title":"Findings plus a spine","scenario":"You surveyed 140 students about the writing center for your capstone, and you're presenting to the center's director. Your draft ends at the findings — wait times deter 60% of would-be users. You're just a student and she runs the place, so recommending feels presumptuous. It isn't; it's the job.","task":"Write the closing 2 sentences: the key finding and your recommendation, owned.","tips":["Data plus silence forces the audience to do your job.","'Based on this, I'd recommend...' is expected from the person who knows the data best.","Scope the recommendation to what your data supports — that's what earns you the right to make it."],"focus":["impact","precision"],"placeholder":"Since wait times deter 60% of would-be users, I recommend piloting drop-in hours during the two weeks before major deadlines."},
    {"id":"presence-stu-mid-12","level":"mid","profession":"student","title":"Volunteering out loud","scenario":"Your professor asks who will present the group's findings to the visiting faculty panel. Silence. You want to do it — it's exactly the experience you need — but your instinct is to wait, catch a teammate's eye, and hope someone nominates you. The moment is three seconds long.","task":"Script the one or two sentences you'd say to claim it directly.","tips":["'I'll do it' — then one clause of why you're suited, if anything.","Waiting to be nominated usually means watching someone else get it.","Claiming work you want is not arrogance; it's how allocation actually happens."],"focus":["impact","concision"]},
    {"id":"presence-stu-mid-13","level":"mid","profession":"student","title":"Proposing the next experiment","scenario":"Your PI asks in lab meeting what you think the group should run next. You have a real view — the temperature series, because it isolates the variable your last run confounded — but grad students are in the room and your habit is to defer: 'whatever makes sense to everyone.'","task":"Script a 2-sentence proposal with your reasoning, delivered as a proposal rather than a deferral.","tips":["You were asked — answering with deference is declining the invitation.","Reason from the data: 'because our last run confounded temperature with time.'","Being wrong confidently and correctably is how undergrads become colleagues."],"focus":["impact","precision"],"placeholder":"I'd run the temperature series next — our last run confounded temperature with incubation time, and this isolates it."},
    {"id":"presence-stu-mid-14","level":"mid","profession":"student","title":"What the data shows versus what I conclude","scenario":"In your lab report discussion, you wrote: 'The enzyme clearly works best at 37 degrees, which proves it evolved for body temperature.' Your TA circled 'proves.' The data shows a peak at 37; the evolutionary story is your interpretation, and blending them costs credibility with every scientific reader.","task":"Rewrite as 2 sentences: one for the observation, one for the labeled interpretation.","tips":["'The data shows' and 'this suggests' head different sentences for a reason.","Overclaiming makes readers doubt your observations, not just your interpretations.","Labeled speculation is welcome in a discussion section; disguised speculation is not."],"focus":["precision","clarity"]},
    {"id":"presence-stu-mid-15","level":"mid","profession":"student","title":"The pitch with the ask up front","scenario":"You want the exec board to approve a mentorship program pairing seniors with first-years. Last time you pitched something, you talked for four minutes before anyone knew what you were asking for, and the board's attention died. This pitch gets ninety seconds.","task":"Write the first 3 sentences: the ask, the two-part reason, and what happens next if they say yes.","tips":["Sentence one contains the ask and its size: approval plus $150 and two exec hours.","Make the structure audible: 'Two reasons. First...'","End with the immediate next step — approvals stall without one."],"focus":["structure","impact"],"placeholder":"I'm asking the board to approve a senior–first-year mentorship pilot: $150 and two exec hours a month."},
    {"id":"presence-stu-mid-16","level":"mid","profession":"student","title":"The graduation question without the flinch","scenario":"At a family gathering, at career fairs, in interviews — 'so what are you doing after graduation?' Your current answer is a nervous laugh and 'honestly, no idea, hopefully something.' You do have a direction: data analytics, probably in healthcare, applying this fall. Uncertainty isn't the problem; the collapse is.","task":"Script a confident 2-sentence answer that states your direction and holds your honest uncertainty.","tips":["A direction with open questions is a plan — say it like one.","'I'm targeting X; the open question is Y' beats 'no idea' and beats false certainty.","People invest in stated directions: leads, introductions, advice all follow."],"focus":["clarity","impact"],"placeholder":"I'm heading into data analytics, ideally in healthcare — applications go out this fall."},
    {"id":"presence-stu-mid-17","level":"mid","profession":"student","title":"Making the call on scope","scenario":"Two nights before the deadline, your group is split: finish the interactive map (impressive, risky) or ship the static version (safe, done tomorrow). The debate is looping. Someone needs to call it, and you're the de facto lead. Your instinct is to keep facilitating; what the group needs is a decision.","task":"Script the 2-3 sentences that end the loop: your call, the reason, and the door you leave open.","tips":["Name the decision moment: 'We've been looping — I'm making the call.'","One reason, the decisive one: the map has an unbounded bug risk.","Leave a principled door open: 'if the map works by noon tomorrow, we swap it in.'"],"focus":["impact","clarity"]},
    {"id":"presence-stu-mid-18","level":"mid","profession":"student","title":"Three asks, visibly numbered","scenario":"You're emailing the department administrator with three requests before the add/drop deadline: a prerequisite override form, a signature confirmation, and a question about wait-list position. Your emails tend to blur into paragraphs, and blurred asks get partial answers.","task":"Write the email's opening line plus the three asks as a visibly numbered list, one line each.","tips":["Announce the count: 'Three requests before Friday's deadline.'","Number them; make each independently answerable.","Structure in an email is presence too — it signals someone organized enough to help quickly."],"focus":["structure","clarity"]},
    {"id":"presence-stu-mid-19","level":"mid","profession":"student","title":"Both sides, then a verdict","scenario":"You moderated your debate club's practice round on tuition policy and you're writing the summary for the newsletter. Your draft presents both sides evenhandedly and ends there. A summary that never lands is a transcript; the newsletter asked for your judge's assessment of which case was stronger and why.","task":"Write the 2-sentence verdict: which side argued better and the one reason that decided it.","tips":["Fair summary first, but a verdict is the deliverable — land one.","Judge the argumentation, not the position: 'the negative won on evidence quality.'","One decisive reason, stated plainly, is what makes a verdict useful."],"focus":["impact","structure"]},
    {"id":"presence-stu-mid-20","level":"mid","profession":"student","title":"'I recommend we...' at the planning meeting","scenario":"The intramural committee is planning the spring tournament and drowning in open questions: bracket size, weekend versus weeknights, whether to charge a fee. You've run the numbers from last year. Every time you speak, you present information and stop short of recommending.","task":"Pick one open question and script a 2-sentence recommendation with its supporting number.","tips":["Attach a recommendation to every analysis you bring — that's the habit.","'Last year weeknight games had 40% forfeits — I recommend weekend-only' is one sentence of data, one of decision.","Meetings end when someone recommends; be that person once per topic."],"focus":["impact","precision"],"placeholder":"Weeknight games forfeited 40% of the time last spring — I recommend we run weekend-only brackets."},
    {"id":"presence-stu-mid-21","level":"mid","profession":"student","title":"The committee presentation, facts fenced","scenario":"You're presenting dining-survey results to a university committee that includes the dining director — who will bristle at anything that sounds like blame. Your findings are genuinely critical: 41% report the meal plan strains their budget. You need the facts to land without your inferences being attackable.","task":"Write 2-3 sentences that present the finding, then your interpretation, explicitly fenced apart.","tips":["Bulletproof the fact: n, question wording, percentage.","Fence the inference: 'The data doesn't say why — my working interpretation is...'","When facts and judgments are separated, attacking your judgment leaves your facts standing."],"focus":["precision","audience"]},
    {"id":"presence-stu-mid-22","level":"mid","profession":"student","title":"Calibrated confidence in the pitch","scenario":"You're pitching your capstone proposal to the review panel. Parts are solid — the dataset is secured, the method is standard. One part is honestly uncertain: whether the sample is big enough for subgroup analysis. Your drafts either project false total confidence or dissolve into wall-to-wall hedging.","task":"Write 2-3 sentences that state the solid parts plainly and flag the one uncertainty precisely.","tips":["Say the sure things like sure things — no hedges where you have none.","Then one precise flag: 'the open risk is subgroup power; here's my fallback.'","Panels trust calibration — uniform confidence and uniform hedging both read as unexamined."],"focus":["clarity","precision"],"placeholder":"The dataset is secured and the method is standard — the one open risk is whether our sample supports subgroup analysis, and my fallback is"},
    {"id":"presence-stu-mid-23","level":"mid","profession":"student","title":"The ambiguous prompt, interpreted","scenario":"The essay prompt can be read two ways, and half the class is confused. You're in office hours. The weak move is 'I don't get the prompt.' You've actually developed a reading: you think it's asking for evaluation, not summary, based on the verb 'assess.' Propose it and confirm.","task":"Script the 2-sentence version: your interpretation with its basis, then the confirmation ask.","tips":["Bring a reading, not a blank: 'I'm reading it as X because Y — is that right?'","Professors remember who engages with ambiguity versus who reports it.","If you're wrong, you'll learn why — which is more than 'I don't get it' ever earns."],"focus":["clarity","impact"]},
    {"id":"presence-stu-mid-24","level":"mid","profession":"student","title":"The handshake introduction","scenario":"A visiting speaker your professor knows is chatting after the lecture, and your professor waves you over: 'This is one of my students.' The next five seconds are yours. Your habit is 'hi, um, I'm just a junior in the department' — 'just' doing a lot of self-erasing work.","task":"Script your one-sentence self-introduction, no 'just,' with one hook worth a follow-up question.","tips":["Delete 'just' from every self-description, permanently.","One concrete hook: what you work on, or the connection to their talk.","The goal of an introduction is a follow-up question — plant one."],"focus":["impact","concision"],"placeholder":"I'm a junior working on the food-access mapping project your talk touched on —"},
    {"id":"presence-stu-mid-25","level":"mid","profession":"student","title":"The tool-switch recommendation","scenario":"Your club's event sign-ups live in a chaos of group-chat messages and a spreadsheet nobody updates. You've researched two sign-up tools and have a clear favorite. At the meeting you could describe both neutrally for five minutes — or make the case in one.","task":"Write the 2-3 sentence recommendation: your pick, the two reasons, and the one-week trial you propose.","tips":["Recommend the winner; mention the runner-up in a clause, not a chapter.","Reasons in the club's terms: less work for organizers, fewer missed sign-ups.","A reversible trial lowers the cost of saying yes — always offer one."],"focus":["impact","structure"]}
  ],
  "answering-under-pressure": [
    {"id":"pressure-stu-mid-01","level":"mid","profession":"student","title":"The cold call you half-heard","scenario":"Your seminar professor cold-calls: 'Do you agree with the author's central claim — yes or no, and why?' Your habit under cold-call adrenaline is to summarize the reading for a minute, hoping an answer emerges. The question was yes or no.","task":"Script a 3-sentence spoken answer that answers the actual question in the first sentence.","tips":["First word territory: 'Mostly yes' or 'No, with one exception.'","Then one reason, then one piece of text.","Summarizing instead of answering reads as not having an answer."],"focus":["clarity","structure"],"placeholder":"Mostly yes — her core claim survives the counterexamples. The one I can't square is"},
    {"id":"pressure-stu-mid-02","level":"mid","profession":"student","title":"The GPA question","scenario":"An interviewer looks up from your resume: 'Your GPA is a 2.9 — what happened?' Your rehearsed instinct is a defensive essay about hard graders and a bad roommate year. What you have that's true and better: a 2.4 first year, a 3.5 since, and a reason the turn happened.","task":"Script a 3-sentence answer: direct acknowledgment, the trajectory with numbers, and forward close.","tips":["Answer the question asked — 'what happened' deserves an actual answer, briefly.","The trajectory is your case: first-year 2.4, 3.5 since. Lead with the turn.","No blame-objects: graders, roommates, professors. Own it and pivot forward."],"focus":["clarity","impact"]},
    {"id":"pressure-stu-mid-03","level":"mid","profession":"student","title":"The hostile methods question","scenario":"During your capstone Q&A, a classmate known for gotchas asks: 'Didn't you basically design a survey guaranteed to get the answer you wanted?' Heat rises in your face. The honest answer: two questions were arguably leading, the core measures weren't, and you have the wording on a backup slide.","task":"Script a 2-3 sentence response that engages the specific criticism without defensiveness.","tips":["Steelman it in half a sentence: 'Fair concern — leading questions are the classic survey failure.'","Then specifics: which items were neutral, and the backup slide with exact wording.","Concede the two weak questions if pressed — partial concession with evidence beats total defense."],"focus":["clarity","precision"],"placeholder":"That's a fair concern to raise about any survey. Two of our ten items were arguably leading — the core four weren't, and here's their exact wording."},
    {"id":"pressure-stu-mid-04","level":"mid","profession":"student","title":"Challenged in front of the group","scenario":"Mid-meeting, a teammate says: 'I don't trust your analysis — the numbers look wrong.' Six people go quiet and look at you. You ran the analysis twice and the numbers are right, but 'no they're not' starts a fight, and folding starts a rumor that your work is shaky.","task":"Script a 2-sentence response with specifics that neither attacks nor folds.","tips":["Ask for the specific: 'Which number looks off?' — vague doubts dissolve under specificity.","State your verification factually: ran it twice, matched the raw export.","Offer the check: 'let's look at the raw file together after' — confidence invites inspection."],"focus":["clarity","precision"]},
    {"id":"pressure-stu-mid-05","level":"mid","profession":"student","title":"'I don't know' with a path","scenario":"Your professor asks, in front of the lecture hall, how your project would handle a data source you've never heard of. Bluffing risks everything; a bare 'I don't know' wastes the moment. The professional move — honest gap plus concrete path — is one you've never practiced aloud.","task":"Script the 2-sentence answer: the honest gap, then the specific path to closing it.","tips":["Clean admission, no squirming: 'I don't know that source.'","Then the path with a deadline: what you'd check and by when.","Reason aloud if you can: 'if it's survey-based like ours, then...' — visible thinking earns partial credit."],"focus":["clarity","impact"],"placeholder":"I don't know that dataset yet — I'll look at its methodology tonight and post whether it fits by tomorrow's discussion."},
    {"id":"pressure-stu-mid-06","level":"mid","profession":"student","title":"The failure question","scenario":"'Tell me about a time you failed.' Your options so far: a humble-brag ('I care too much about deadlines'), or an unprocessed ramble about the club event that flopped. The flop is actually the right story — 12 people came to an event planned for 60 — you've just never told it with a shape.","task":"Script a 4-sentence answer: the failure stated plainly, the cause you own, what changed, the proof it changed.","tips":["Name the failure with a number — '12 people at an event planned for 60' — no cushioning.","Own a cause that was yours: promoted only through one channel, never tested interest.","Spend most words on what changed and the later event that proved it."],"focus":["structure","impact"]},
    {"id":"pressure-stu-mid-07","level":"mid","profession":"student","title":"'Your section is the weak one'","scenario":"At the project check-in, your professor says: 'The literature review is the weakest part of the draft — it reads like a list. That's your section, isn't it?' The group is watching. Deflecting onto the deadline or the group's outline will read exactly like what it is.","task":"Script a 2-3 sentence response that owns the assessment and gets concrete about the fix.","tips":["Agree with what's true first: 'It is — it summarizes without synthesizing.'","Convert critique into spec: ask what good looks like, or state your fix.","Commit to a date. Ownership plus deadline reads as strength, not weakness."],"focus":["clarity","impact"]},
    {"id":"pressure-stu-mid-08","level":"mid","profession":"student","title":"The open-meeting budget challenge","scenario":"At the club's general meeting, a member stands up: 'Why did exec spend $300 on a retreat while cutting the tournament budget? Seems like exec just funds its own fun.' Thirty members are watching. You made this decision as treasurer, and there was a real reason.","task":"Script a 3-sentence answer: the direct answer, the reasoning with numbers, and the accountability offer.","tips":["Answer the accusation's factual core first — what was spent on what.","Give the reasoning you actually used: retention data, planning output, cost per member.","Offer the books: 'the full budget is posted — challenge any line.' Transparency defuses motive theories."],"focus":["clarity","precision"]},
    {"id":"pressure-stu-mid-09","level":"mid","profession":"student","title":"'Why you and not the others?'","scenario":"The scholarship interview is going well until: 'We have forty applicants with your GPA. Why should this be yours?' Comparing yourself to unknown others is a trap; ranking yourself above them is arrogance; deflecting ('anyone here deserves it') wastes the question.","task":"Script a 2-3 sentence answer that makes your specific case without disparaging or deflecting.","tips":["Don't rank people — differentiate paths: name what's genuinely uncommon about yours.","Tie it to the scholarship's stated purpose; the fit is the argument.","One vivid specific — the program you built, the circumstance you carried — beats any adjective."],"focus":["impact","audience"],"placeholder":"I can't speak to the other files, but I can tell you what's unusual about mine:"},
    {"id":"pressure-stu-mid-10","level":"mid","profession":"student","title":"The dinner-table interrogation","scenario":"A relative at dinner: 'Philosophy? What kind of job does that get you?' The mocking edge makes you want to fight or flee. But the question, taken literally, has an answer — you know the fields majors enter and your own plan — and answering it calmly ends the conversation better than either instinct.","task":"Script a 2-sentence answer that takes the question at face value and answers it with specifics.","tips":["Strip the tone, answer the content — the calmest power move available.","Concrete fields and your actual plan: law school apps, LSAT date.","One sentence of substance beats five of justification. Don't over-defend."],"focus":["clarity","concision"]},
    {"id":"pressure-stu-mid-11","level":"mid","profession":"student","title":"The regrade pushback","scenario":"You emailed the TA asking for a regrade on question 3; the reply: 'Your answer didn't demonstrate understanding of the mechanism — the grade stands.' You believe your answer does show the mechanism, in the second paragraph. Replying angry ends the appeal; replying vague ends it slower.","task":"Write a 2-3 sentence reply that responds to the TA's exact stated reason.","tips":["Quote their standard back: 'understanding of the mechanism' — then point to where you showed it.","Line-level specificity: 'second paragraph, where I trace the intermediate step.'","Ask for a look at that paragraph specifically — a bounded ask is grantable."],"focus":["precision","clarity"]},
    {"id":"pressure-stu-mid-12","level":"mid","profession":"student","title":"The yes/no you keep essay-ing","scenario":"Your professor stops you mid-office-hours: 'Simple question — did you run the normality check before the t-test, yes or no?' You didn't, and you feel the essay forming: the tutorial you followed, the time crunch, your general conscientiousness. The question has a one-word answer.","task":"Script the answer: the one word first, then one sentence, no more.","tips":["'No' is a complete first sentence.","Then at most one useful sentence: 'I'll run it today and update the results.'","The essay you want to give is for you, not for them — skip it."],"focus":["concision","clarity"],"placeholder":"No — I missed it. I'll run it today and flag whether anything changes."},
    {"id":"pressure-stu-mid-13","level":"mid","profession":"student","title":"Cross-examination concession","scenario":"In debate cross-ex, your opponent traps you: 'Do you admit your own source says the policy failed in three states?' It does say that — and your case survives it, because the three states lacked the funding mechanism you're proposing. Denying the quote destroys your credibility; conceding without the distinction destroys your case.","task":"Script the 2-sentence response: clean concession, then the distinction that saves the argument.","tips":["Concede fast and specifically: 'Yes, three states, and here's what those three shared.'","The distinction is your whole answer — funded versus unfunded implementations.","Slow concessions read as dishonest; fast ones buy you the room's ear for the distinction."],"focus":["clarity","structure"]},
    {"id":"pressure-stu-mid-14","level":"mid","profession":"student","title":"The weakness question, actually answered","scenario":"'What's your biggest weakness?' You've been coached into 'I'm a perfectionist.' Interviewers hear that daily and mark it as an evasion. You have a real one that's safe to name: you over-prepare and struggle to start before you feel ready — it cost you a deadline once, and you've built a fix.","task":"Script a 3-sentence answer: the real weakness, the concrete cost, the working fix.","tips":["Name a true weakness that isn't disqualifying for this role.","One concrete instance where it cost you — that's what makes it credible.","The fix must be specific and current: 'I now set a start-by date, not just a due date.'"],"focus":["clarity","impact"],"placeholder":"I over-prepare — I delay starting until I feel fully ready, which once cost me"},
    {"id":"pressure-stu-mid-15","level":"mid","profession":"student","title":"'Did you even do the reading?'","scenario":"In your study group, you offer an interpretation and a classmate snorts: 'Did you even do the reading? That's not what it says.' You did the reading. Your interpretation may still be wrong — or theirs is. The next sentence decides whether this is a fight or a productive disagreement.","task":"Script a 2-sentence response that skips the insult and goes straight to the text.","tips":["Don't defend your diligence — redirect to the evidence: 'Show me the passage you're reading.'","Bring yours: 'I'm going off the section where she says...'","Two people pointing at text is scholarship; two people trading credentials is noise."],"focus":["clarity","precision"],"placeholder":"Walk me through the passage you're thinking of — I'm basing mine on the part where she says"},
    {"id":"pressure-stu-mid-16","level":"mid","profession":"student","title":"The contradicting study","scenario":"After your presentation, a classmate raises her hand: 'A study we read in another class found the opposite of your result. How do you explain that?' You don't know the study. You do know your own methods and the usual reasons results diverge: different populations, measures, timeframes.","task":"Script a 2-3 sentence answer that's honest about not knowing the study but substantive about divergence.","tips":["Admit the specific gap fast: 'I don't know that study.'","Then reason from what you do know: the usual sources of divergence, and which your design is vulnerable to.","Ask for the citation — publicly, with interest. It converts a challenge into a collaboration."],"focus":["clarity","structure"]},
    {"id":"pressure-stu-mid-17","level":"mid","profession":"student","title":"'How long will your part take?'","scenario":"In the group meeting, the project manager type asks: 'How long for your data section — I'm building the timeline right now.' Your honest self-knowledge: about six hours of work, but you have two midterms, so realistically done Thursday. Your habit is a vague 'shouldn't take too long.'","task":"Script the one-sentence answer with a number and a date.","tips":["They asked for a duration — give hours and a calendar date.","Build in your real constraints silently; promise the date you'll actually hit.","'Shouldn't take too long' makes their timeline a fiction — a number makes it a plan."],"focus":["precision","concision"],"placeholder":"About six hours of work — with my midterms, done by Thursday night."},
    {"id":"pressure-stu-mid-18","level":"mid","profession":"student","title":"The advisor's challenge to your overload","scenario":"You've asked your advisor to approve an 18-credit semester with a part-time job. She pushes: 'Students who try this usually drop a course by week six. Why are you different?' It's a fair challenge with data behind it. You have an actual answer — you did 16 credits plus the same job last term at a 3.6.","task":"Script a 2-sentence response that engages her evidence with yours.","tips":["Treat the pushback as data, not opposition — she's shown you the base rate.","Answer with your own record: the nearest comparable semester you've completed.","Offer the safety valve: the course you'd drop first if it cracks. Planning for failure is the credible move."],"focus":["precision","impact"]},
    {"id":"pressure-stu-mid-19","level":"mid","profession":"student","title":"'Why did you leave?'","scenario":"The interviewer noticed: 'You were in the pre-law society for a year and left — what happened?' The full truth involves a personality clash with the president. Airing that torches you; lying risks worse. There's also a true, clean version: your interests shifted to policy work and you put the hours into the policy journal instead.","task":"Script a 2-sentence answer that's honest, brief, and doesn't badmouth anyone.","tips":["Short and true beats complete: the interest shift is real — lead with it.","Never criticize the organization or its people; interviewers map it onto themselves.","Land forward: what the hours went to instead, and what that produced."],"focus":["clarity","audience"]},
    {"id":"pressure-stu-mid-20","level":"mid","profession":"student","title":"The demo that dies on stage","scenario":"Ninety seconds into your class demo, the app white-screens. Fifteen classmates and your professor watch you refresh twice. Nothing. You have screenshots on the next slides, and you know exactly what the demo was going to show. The next ten seconds of talking determine the room's memory of this presentation.","task":"Script the 2 sentences you'd say to keep command of the room and pivot.","tips":["Name it lightly, once — no extended apology, no fiddling in silence.","Pivot on rails: 'The screenshots show exactly what you'd have seen.'","The audience takes its cue from you; calm narration converts a failure into composure evidence."],"focus":["clarity","impact"],"placeholder":"That's the live-demo tax — let me show you the same flow in screenshots, which honestly are easier to follow anyway."},
    {"id":"pressure-stu-mid-21","level":"mid","profession":"student","title":"'That's not what the author argues'","scenario":"You attribute a claim to the author in seminar, and the professor says flatly: 'That's not what she argues.' Panic offers two bad exits: instant total retreat ('oh, sorry, never mind') or stubborn doubling down. The good exit runs through the text you have open in front of you.","task":"Script the 1-2 sentence response that checks the text before folding or fighting.","tips":["Buy the beat: 'Let me find what I was reading' — and actually go to the page.","If you misread, name the misreading crisply; that's a skill, not a defeat.","If the passage supports you, read it aloud and ask — 'how do you read this line?' is respectful and strong."],"focus":["precision","clarity"]},
    {"id":"pressure-stu-mid-22","level":"mid","profession":"student","title":"The safety grilling","scenario":"Your proposal for an off-campus club hike hits the student-activities committee, and the questions turn sharp: 'What if someone is injured two miles from the trailhead? Who's liable? Has anyone here done wilderness first aid?' You prepared for some of this; one question — liability — you genuinely can't answer.","task":"Script a 3-sentence response: answer what you prepared, flag what you can't, propose the follow-up.","tips":["Answer the prepared parts with specifics: route, cell coverage, the certified member.","One clean 'I can't answer the liability question today' beats an improvised legal theory.","Propose the concrete follow-up: written answer from risk management by Friday. Committees accept process."],"focus":["clarity","structure"]},
    {"id":"pressure-stu-mid-23","level":"mid","profession":"student","title":"The campus reporter's pointed question","scenario":"You sit on the student-government budget committee that cut arts funding 15%. A campus reporter catches you after the meeting: 'Students are calling this cut hostile to the arts. Were you trying to defund the arts program?' Whatever you say may be quoted, exactly and without context.","task":"Script a 2-sentence on-the-record answer: the direct no, and the reason with its numbers.","tips":["Answer the actual accusation first: 'No.' Then the affirmative case in quotable form.","Speak in complete, self-contained sentences — fragments get reassembled.","No speculation, no 'off the record,' no answering questions that weren't asked."],"focus":["clarity","precision"],"placeholder":"No — every category was cut this year because activity-fee revenue fell 12%, and arts was cut less than average."},
    {"id":"pressure-stu-mid-24","level":"mid","profession":"student","title":"The three-part question","scenario":"During Q&A a professor stacks a question: 'What's your sample size, why didn't you control for major, and doesn't that undermine your second conclusion?' Your instinct is to answer the last part — the scariest — and forget the rest, leaving the audience with the impression you dodged.","task":"Script the answer's opening structure: name the parts, then take them in order, one line each.","tips":["Signpost first: 'Three parts — size, controls, and the implication. In order:'","Answer parts in the asked order; skipping one looks evasive even when accidental.","The scary part goes last anyway — and lands better after two solid answers."],"focus":["structure","clarity"]},
    {"id":"pressure-stu-mid-25","level":"mid","profession":"student","title":"'Convince me in one minute'","scenario":"The case-competition judge leans back: 'You have one minute. Convince me your recommendation isn't just the safe pick.' The clock is running. You have a real answer — the 'bold' option your competitors chose fails on unit economics — but a minute of pressure usually turns your answers into lists of everything you know.","task":"Script the 3-4 sentence one-minute answer: one claim, one number, one contrast, one close.","tips":["One argument, fully landed, is what a minute holds — pick your best.","The number is the spine: name the unit economics that kill the bold option.","Close by re-framing: 'It's not the safe pick — it's the only one that survives the math.'"],"focus":["impact","concision"],"placeholder":"It's not the safe pick — it's the only one that survives the math."}
  ],
  "narrative-and-persuasion": [
    {"id":"narrative-stu-mid-01","level":"mid","profession":"student","title":"Moving the meeting time","scenario":"You want to move club meetings from Thursday 8pm to Sunday 4pm — the data from your member survey supports it. But 'the survey says' hasn't moved anyone. The members in the room are the ones Thursday works for; the members Thursday excludes aren't there to argue.","task":"Write a 3-sentence persuasive case that makes the absent members' stakes vivid to the present ones.","tips":["Make the invisible cost concrete: name what the club loses — the 14 members who voted for a change and stopped coming.","Frame as before/after: what Sundays makes possible that Thursdays kills.","Pre-empt the room's objection — 'Thursday works fine' — for whom?"],"focus":["impact","audience"],"placeholder":"Fourteen members told us Thursday is why they stopped coming — we're voting on their behalf tonight, not ours."},
    {"id":"narrative-stu-mid-02","level":"mid","profession":"student","title":"The cover letter with an arc","scenario":"Your cover letter for a UX internship lists qualities: creative, detail-oriented, team player. Flat. What you have is a story with a shape: the club website was getting 30 visits a month, you redesigned it around what new members actually searched for, and visits quadrupled during recruitment.","task":"Write the 3-sentence before/after version for the letter's middle paragraph.","tips":["Before state, with its number. Your intervention, specifically. After state, with its number.","The arc proves 'creative' and 'detail-oriented' without using either dead word.","Keep yourself the actor: 'I rebuilt' not 'the site was rebuilt.'"],"focus":["impact","structure"]},
    {"id":"narrative-stu-mid-03","level":"mid","profession":"student","title":"Petitioning for the deadline change","scenario":"Three major deadlines across two departments land on the same Friday, and you're drafting the email asking your professor to move hers. She's heard 'we have other deadlines' every semester and holds the line, because moving it once means moving it always. That objection will be her first thought.","task":"Write a 3-sentence request that pre-empts her strongest objection instead of hoping she won't have it.","tips":["Name her objection before she does: a one-off exception becomes a precedent.","Then answer it: propose the narrow version — 48 hours, this section, this semester, tied to the documented triple-collision.","Bring receipts: the three syllabi, attached. Verifiable claims move people who've heard it all."],"focus":["impact","structure"]},
    {"id":"narrative-stu-mid-04","level":"mid","profession":"student","title":"Pitching the club into existence","scenario":"You're proposing a new club — competitive coding — to the student activities board. Your draft argues you deserve to exist: you have interest, you have a mission statement. Boards approve maybe half of proposals, and they approve the ones that fill a hole they can see.","task":"Write the 3-sentence pitch framed around the gap, not around your enthusiasm.","tips":["Open with the hole: 200 CS majors, zero competitive programming outlet, students leaving for other schools' Discord servers.","The before/after: what exists now versus campus with your club in it.","Answer the board's real question — will this still exist in two years? Name your succession plan."],"focus":["impact","audience"],"placeholder":"Two hundred CS majors have nowhere on campus to practice competitive coding — they're joining other universities' online teams instead."},
    {"id":"narrative-stu-mid-05","level":"mid","profession":"student","title":"Selling the scope cut","scenario":"Your group's app has five planned features and, at the current pace, three will be half-broken at the demo. You want to cut two features now. To the group this sounds like defeatism — they hear 'we do less.' You need them to hear what you see: the difference between demoing three polished features and five broken ones.","task":"Write the 2-3 sentence case, framing the cut as choosing the better demo, with the stakes concrete.","tips":["Paint both futures specifically: the professor clicking a broken feature versus three that work flawlessly.","The stake is the grade and the demo-day story — name them.","Pre-empt 'but we promised five': the proposal doc can note descoped features with reasons — that's rigor, not retreat."],"focus":["impact","clarity"]},
    {"id":"narrative-stu-mid-06","level":"mid","profession":"student","title":"The scholarship essay's change arc","scenario":"The essay prompt: 'Describe a challenge that shaped you.' Your draft describes the challenge — your family's restaurant closing during your first year — in vivid detail, but you at the end of the essay are indistinguishable from you at the beginning. Committees fund trajectories, not hardships.","task":"Write the 2-sentence 'after' passage: who the events made you, with evidence that the change is real.","tips":["The challenge is the setup; the essay's cargo is the change in you.","Prove the change with behavior: what you do now that you didn't before.","Connect the change to what you'll do with the scholarship — the arc should point through the award."],"focus":["impact","structure"],"placeholder":"Closing the restaurant taught me what I do now by reflex: I read the numbers before the mood."},
    {"id":"narrative-stu-mid-07","level":"mid","profession":"student","title":"Recruiting a supervisor for the independent study","scenario":"You want Professor Okafor to supervise an independent study on housing policy. Supervising is unpaid extra work, and she declines most requests. Your draft email is about what you want to learn. Her decision will turn on something else: whether this costs her much and whether you'll actually finish.","task":"Write the 3-sentence pitch aimed at her decision factors, not just your enthusiasm.","tips":["Reduce her cost visibly: a syllabus you've already drafted, biweekly 30-minute check-ins, deliverables she just reacts to.","Prove you finish things: the one course or project of hers where you delivered.","Connect to her interests — cite her own work and where yours feeds it."],"focus":["audience","impact"]},
    {"id":"narrative-stu-mid-08","level":"mid","profession":"student","title":"The unpaid internship conversation","scenario":"You've been offered an unpaid summer internship at a legal-aid nonprofit — the exact experience law schools want to see. Your parents expect you to do the paid warehouse job again. Their objection is real and financial. Telling them the internship 'matters more than money' will lose; you need the arithmetic and the arc.","task":"Script the 3-sentence case: acknowledge the cost, show the coverage plan, frame the payoff concretely.","tips":["Lead into their objection, not around it: name the $4,000 gap yourself.","Show the plan: savings, part-time weekend shifts, the specific numbers.","Make the payoff concrete: what this line on the resume does for law school applications — with an example if you have one."],"focus":["audience","impact"]},
    {"id":"narrative-stu-mid-09","level":"mid","profession":"student","title":"The donor email that's about the donor","scenario":"Your club's fundraising email for the robotics competition is entirely about the club: our team, our season, our goals. Alumni donors delete these. What makes alumni give: their own story reflected back — and knowing exactly what their $50 does.","task":"Rewrite the email's core 2-3 sentences aimed at the alum's stakes and memory.","tips":["Open in their world: 'You remember what the lab felt like at 2am before a build deadline.'","Make $50 concrete: one competitor's registration, the motor kit for one rookie team.","The before/after: this team without funding, this team funded. One vivid image each."],"focus":["audience","impact"],"placeholder":"Your $50 registers one first-year for the regional — the same competition that"},
    {"id":"narrative-stu-mid-10","level":"mid","profession":"student","title":"Winning the topic vote","scenario":"Your project group votes on a topic tomorrow, and you're backing food insecurity on campus over the trending pick, social-media sentiment analysis. Your topic has an unglamorous surface but a decisive advantage: the campus food pantry has offered its usage data — real, exclusive, and analyzable in the time you have.","task":"Write the 2-3 sentence pitch that reframes the choice from 'exciting topic' to 'exciting result.'","tips":["Reframe the axis: not which topic sounds better, but which produces a finding nobody else has.","Make the contrast concrete: scraping the same Twitter data as every other group versus exclusive pantry records.","Pre-empt the objection — 'it sounds depressing' — by naming the headline finding you might get."],"focus":["impact","structure"]},
    {"id":"narrative-stu-mid-11","level":"mid","profession":"student","title":"The op-ed pitch","scenario":"You want the campus paper to run your op-ed about the library closing at midnight during finals. Your draft pitch to the editor summarizes your argument. Editors don't buy arguments; they buy pieces their readers will click, share, and fight about in the comments.","task":"Write the 2-sentence pitch framed around what the piece does for the paper's readers.","tips":["Pitch the collision: every student has stood outside those doors at 12:01 during finals week.","Name the villain-shaped fact: the library's own usage data peaks the exact week hours shrink.","One line on timing: finals start in three weeks — run it now or it's dead."],"focus":["audience","impact"]},
    {"id":"narrative-stu-mid-12","level":"mid","profession":"student","title":"The story only you can tell","scenario":"'Walk me through your resume' openers keep producing the same flat chronology from you: majors, clubs, jobs, in order. The interviewer forgets you by lunch. Buried in your chronology is an actual throughline — everything you've chosen involves translating between technical people and everyone else — and a story that proves it.","task":"Script a 3-4 sentence answer with a change arc: where you started, what you discovered, what you built because of it.","tips":["Find the throughline first; the resume becomes evidence for it instead of a list.","One scene, told with texture — the moment you discovered the pattern — carries the whole answer.","End where the job is: 'which is why this role.' The arc should land on their doorstep."],"focus":["structure","impact"],"placeholder":"Everything on that page is the same move: standing between technical people and everyone else. It started when"},
    {"id":"narrative-stu-mid-13","level":"mid","profession":"student","title":"The quiet-hours proposal","scenario":"You're proposing a residence-council policy: enforced quiet hours during finals week. Half the council thinks it's unenforceable nanny-stuff. Your draft argues from your own suffering — the 2am hallway parties before your chemistry final. One person's complaint isn't a policy case.","task":"Write the 2-3 sentence case that scales your story into the building's stakes and pre-empts 'unenforceable.'","tips":["Scale up: from your 2am story to the 40 residents with 8am finals that week.","Pre-empt the enforcement objection with the modest version: posted hours plus RA-backed complaints, like three other residence halls already run.","Concrete stakes: name what a final is worth in a course grade."],"focus":["impact","structure"]},
    {"id":"narrative-stu-mid-14","level":"mid","profession":"student","title":"The volunteer ask that names the change","scenario":"Your club needs eight volunteers for Saturday's charity 5K, and your draft message is a plea: 'we really need help, please sign up.' Pleading recruits the same three loyalists. What recruits the other five: a concrete picture of what their four hours produces, and a job with a name.","task":"Rewrite the ask in 2-3 sentences: the concrete outcome their hours buy, and specific named roles.","tips":["'We need help' recruits nobody; 'we need a finish-line timer' recruits a person.","Name the stake: every runner's entry fee is a meal packed at the food bank — do the math out loud.","Lower the threshold: exact hours, exact place, breakfast included."],"focus":["impact","audience"],"placeholder":"Four hours Saturday morning = 120 runner check-ins = $1,800 for the food bank. We need two greeters, a timer, and"},
    {"id":"narrative-stu-mid-15","level":"mid","profession":"student","title":"Saving the course","scenario":"The department is cutting its only science-writing course for low enrollment, and you're drafting the student letter asking them to keep it. 'We love this course' is the draft's whole argument. The department's decision runs on numbers and mission — and you have access to both: the course's outcomes and the reason enrollment looks low.","task":"Write the letter's core 3 sentences: the counter-fact on enrollment, the outcome evidence, the stake in the department's own terms.","tips":["Attack the premise: enrollment is low because it's scheduled against the major's required lab.","Outcome evidence: name where the course's alumni landed — the science-journalism placements.","Frame in their mission language: the department's own strategic plan promises communication training."],"focus":["impact","precision"]},
    {"id":"narrative-stu-mid-16","level":"mid","profession":"student","title":"Converting the internship","scenario":"Your summer internship ends in three weeks, and you want to pitch your supervisor on keeping you ten hours a week during the semester. She hasn't budgeted for it. Your draft asks for the favor; the winning version sells the asset — you're trained, you know the systems, and rehiring in January costs her six weeks of onboarding.","task":"Write the 3-sentence pitch framed around her costs and gains, not your hopes.","tips":["Lead with her problem: the fall project load and the onboarding cost of anyone new.","Quantify yourself: trained on the CRM, wrote the process doc, zero ramp-up.","Shrink the risk: propose a one-month trial at ten hours, revisit in October."],"focus":["audience","impact"],"placeholder":"Rehiring in January means six weeks of onboarding — keeping me at ten hours a week means zero."},
    {"id":"narrative-stu-mid-17","level":"mid","profession":"student","title":"The debate opening that disarms first","scenario":"You're opening for the affirmative on a campus-wide laptop ban in lectures. You know exactly what the negative will lead with — accessibility needs and note-taking research — because it's what you'd lead with. Standard openings save rebuttal for later; the stronger move is to plant your answer before they speak.","task":"Script a 3-sentence opening that pre-empts the strongest objection inside your own case.","tips":["Name their best argument yourself, fairly — the audience trusts whoever steelmans.","Then the pivot: your proposal exempts documented accommodations, so the real question is the other 90%.","Pre-emption converts their opener into an echo of something you already handled."],"focus":["structure","impact"]},
    {"id":"narrative-stu-mid-18","level":"mid","profession":"student","title":"Changing the study group's method","scenario":"Your study group preps for the biochem final the way it always has: everyone rereads notes together. It produced three Cs on the midterm. You want to switch to practice-problem sessions — the method the evidence and the course's own exams favor. 'We've always done it this way' is the room's inertia.","task":"Write the 2-3 sentence case anchored to the midterm result and one concrete stake.","tips":["The midterm is your evidence: rereading produced three Cs — name it without blaming anyone.","Before/after the method, not the people: same hours, different output.","Propose the reversible trial: two sessions the new way, then compare against the practice midterm."],"focus":["impact","precision"]},
    {"id":"narrative-stu-mid-19","level":"mid","profession":"student","title":"The grant application's before/after","scenario":"Your club is applying for a $2,000 community-impact grant to expand its free tutoring program. Your draft says the money would 'help us grow and reach more students.' Every applicant says that. What you have: 30 kids tutored weekly now, a 40-family waitlist, and a costed plan to clear it.","task":"Write the 2-3 sentence impact statement structured as funded-versus-unfunded futures.","tips":["Two futures, side by side: without funding, the 40-family waitlist stays; with it, cleared by March.","Cost-per-outcome is grant language: $2,000 across 40 kids is $50 per child per semester — say it.","Evidence you can execute: the program already runs; the grant scales what works."],"focus":["impact","precision"],"placeholder":"Without this grant, 40 families stay on our waitlist through spring; with it, every one is matched to a tutor by March — $50 per child."},
    {"id":"narrative-stu-mid-20","level":"mid","profession":"student","title":"The co-hosting objection","scenario":"You want your entrepreneurship club to co-host pitch night with the finance society — double the audience, split the costs. Your exec board's unspoken fear: co-hosting dilutes the club's brand and the finance society takes the credit. If you don't surface that fear, it votes against you silently.","task":"Write the 2-3 sentence pitch that names the brand fear out loud and answers it with specifics.","tips":["Say the quiet part first: 'The worry is they get the credit — here's how we prevent that.'","Answer with mechanics: co-equal logos, our president opens, split emcee duties — negotiated up front.","Then the prize with numbers: their 200-member list, our 80, half the catering bill."],"focus":["audience","structure"]},
    {"id":"narrative-stu-mid-21","level":"mid","profession":"student","title":"Selling the revision plan","scenario":"Peer feedback on your group's draft came back rough, and the group's instinct is cosmetic: fix the typos, resubmit. You've mapped the feedback and it clusters into one deep problem — the analysis never connects to the research question. You want the group to commit to a real restructure with nine days left.","task":"Write the 2-3 sentence case that makes the deep fix feel achievable, with the stakes named.","tips":["Show the map: twelve comments, one root cause — that's actually good news, and frame it that way.","Make the fix concrete and sized: rewrite two transition sections, six hours split across four people.","Contrast the futures: typo-fixed C-plus versus restructured B-plus/A-minus, using the rubric's own weights."],"focus":["impact","structure"]},
    {"id":"narrative-stu-mid-22","level":"mid","profession":"student","title":"The statement of purpose's spine","scenario":"Your master's program statement of purpose reads as a list of enthusiasms: you liked your stats courses, you liked your research assistantship, you like the program. Admissions readers want an arc with an engine — each experience generating the question that the next one answered, pointing at their program.","task":"Write the 2-3 sentence arc skeleton: the originating question, the experience that sharpened it, why this program is the necessary next step.","tips":["Cause and effect, not chronology: each stage should make the next inevitable.","The program must be the answer to your specific question — name the lab, methods, or faculty that make it so.","'I've always been passionate about' is the opening to cut; start inside the story."],"focus":["structure","impact"],"placeholder":"The question that hooked me in my assistantship — why do interventions that work in trials fail in schools? — is the exact question your implementation-science lab exists to answer."},
    {"id":"narrative-stu-mid-23","level":"mid","profession":"student","title":"The unconventional angle, defended","scenario":"You want to write your term paper analyzing protest movements through the economics of attention rather than the standard frameworks from the syllabus. Your professor is open-minded but rigorous; her worry will be that 'creative' means 'avoiding the course material.' You're pitching it in office hours tomorrow.","task":"Script the 2-3 sentence pitch that pre-empts the rigor objection and anchors the angle in the course.","tips":["Pre-empt directly: name the two course frameworks your analysis will still engage, and where.","Show the payoff: what the attention lens explains that the standard lens can't — one concrete case.","Offer the checkpoint: an outline by Friday so she can redirect before you're deep in."],"focus":["audience","structure"]},
    {"id":"narrative-stu-mid-24","level":"mid","profession":"student","title":"The campaign speech with one promise","scenario":"You're running for student-government treasurer, and you have ninety seconds at the candidates' forum. Every opponent will promise transparency, communication, and change. Your draft promises the same three abstractions. You have one concrete thing they don't: a plan to publish every club's budget in a public dashboard by October.","task":"Write the 3-sentence core of the speech built around the one concrete promise and its stakes.","tips":["One promise, dated and checkable, beats five abstractions — voters remember the specific.","Stake it in their experience: every club treasurer who waited six weeks to learn their budget.","Make the accountability explicit: 'If it's not live by October, don't re-elect me.' Falsifiability is charisma."],"focus":["impact","concision"],"placeholder":"One promise, one date: every club budget in a public dashboard by October 1."},
    {"id":"narrative-stu-mid-25","level":"mid","profession":"student","title":"Retiring the legacy event","scenario":"You're proposing the club retire its annual formal — attendance has halved twice, it loses $600 a year, and the volunteers who run it are burning out. But the formal is the club's oldest tradition, and the alumni group chat will erupt. A pure numbers case will read as soulless; a pure feelings case will change nothing.","task":"Write the 3-sentence case that honors what the event was, names what it costs now, and frames the ending as stewardship.","tips":["Honor first, honestly: what the formal meant is the reason this decision is hard — say so.","Then the unflinching numbers: attendance halved twice, $600 yearly loss, three burned-out organizers.","Frame retirement as protecting the mission: name what the $600 and volunteer hours become instead."],"focus":["impact","audience"]}
  ],
  "delivering-hard-messages": [
    {"id":"hard-stu-mid-01","level":"mid","profession":"student","title":"Telling the group you're dropping","scenario":"Week six, and you've decided to drop the course your four-person project group is counting on you for. You own the data section. Every day you delay telling them makes their scramble worse, but your draft message is three paragraphs of apology that never quite says the words.","task":"Write a 3-sentence message that states the decision in sentence one and moves fast to what you'll hand over.","tips":["Sentence one: 'I'm dropping the course, effective this week.' No softening preamble.","The kindest part is the handover: what's done, where it lives, what remains.","Apologize once, cleanly — then be useful."],"focus":["clarity","impact"],"placeholder":"I've decided to drop the course, effective Friday — I know that affects the data section, so here's the handover:"},
    {"id":"hard-stu-mid-02","level":"mid","profession":"student","title":"The missed deadline, unpadded","scenario":"The paper was due at midnight and you didn't submit — you misjudged the week completely. Your draft email to the professor is a wall of context: your shifts, your other midterms, your laptop trouble. Somewhere in paragraph three is the actual message. Professors read these daily and know padding when they see it.","task":"Write the 3-sentence version: the fact, one honest sentence of ownership, the specific ask.","tips":["Front-load the fact: the paper wasn't submitted and that's on you.","One reason maximum, only if true and brief — a list of reasons reads as a list of excuses.","End with a concrete ask: the late policy applied, or a 48-hour submission — name it."],"focus":["clarity","concision"]},
    {"id":"hard-stu-mid-03","level":"mid","profession":"student","title":"The clean no to a friend","scenario":"A good friend in your course asks to copy your problem set — 'just to see the structure, I'll change the numbers.' The syllabus calls this a reportable violation for both of you. 'Maybe, I don't know, we'll see' just delays this to a worse moment tonight.","task":"Script the 2-sentence no: clear refusal, no lecture, one real alternative.","tips":["The no comes first and complete: 'No — I can't share my solutions.'","Skip the ethics lecture; the reason can be one clause ('we'd both be on the line').","Offer what you can give: an hour tonight working through the approach together."],"focus":["clarity","concision"],"placeholder":"No — I can't share my write-up; we'd both be on the line. But I'll walk through the approach with you tonight."},
    {"id":"hard-stu-mid-04","level":"mid","profession":"student","title":"The event that lost money","scenario":"A club member poured weeks into organizing the speaker showcase. It lost $400 and drew 25 people to a 100-seat room. She's proposing to run it again next semester, bigger. As president, you've decided it won't repeat — and she deserves to hear that from you, directly, with the numbers.","task":"Write the 3-sentence message: the decision, the numbers behind it, and what her effort earned that's real.","tips":["Decision first: the showcase won't run next semester.","Numbers make it about the event, not about her: $400 loss, 25% attendance.","Genuine credit only — name the specific thing she did well, and where that skill goes next."],"focus":["clarity","impact"]},
    {"id":"hard-stu-mid-05","level":"mid","profession":"student","title":"Behavior, impact, ask","scenario":"Your project teammate has missed three of the last four meetings, and the group redistributes his work each time in resentful silence. You're going to say something — to him, directly, before it goes to the professor. Your draft oscillates between too soft ('no worries, but...') and character judgment ('you clearly don't care').","task":"Write the 3-sentence version: the specific behavior, its concrete impact, the specific ask.","tips":["Behavior is countable: three of four meetings, with dates — not 'you always.'","Impact is what the group did as a result: redistributed the modeling work twice.","The ask is forward-looking and answerable: commit to Thursdays or trade for async work."],"focus":["precision","clarity"],"placeholder":"You've missed three of our last four meetings, and each time we've redistributed your section that night."},
    {"id":"hard-stu-mid-06","level":"mid","profession":"student","title":"Declining the presidency","scenario":"The outgoing president of your club has been grooming you to take over, and the nomination meeting is Sunday. You've decided no — your senior thesis and applications need the hours. She'll be disappointed, and she'll hear it as rejection of her mentorship unless you separate the two.","task":"Write the 3-sentence message: the clear no, the real reason, and what you're still willing to do.","tips":["Say no to the role, not the person — name what her mentorship meant, briefly and specifically.","The reason should be true and final; a negotiable-sounding reason invites a renegotiation.","Offer the bounded alternative: training the new president, running one event — only if you mean it."],"focus":["clarity","audience"]},
    {"id":"hard-stu-mid-07","level":"mid","profession":"student","title":"'Your section needs a rewrite'","scenario":"The group paper is due Monday, and your teammate's section — turned in proudly, on time — doesn't answer the assigned question. It's well-written material for a different prompt. Someone has to tell her today, and the group chat has voted it's you. Vague 'maybe tweak a few things' feedback guarantees a Monday disaster.","task":"Write the 3-sentence message: the honest verdict, the specific gap, the concrete offer.","tips":["Verdict first, kindly and plainly: the section needs restructuring before Monday, not tweaks.","Name the specific gap: the prompt asks for causes; the section describes effects.","Make the path real: the two paragraphs that can be saved, and an offer to outline it together tonight."],"focus":["clarity","impact"]},
    {"id":"hard-stu-mid-08","level":"mid","profession":"student","title":"Resigning mid-semester","scenario":"You're the club's events coordinator, and between your new job and your course load, you're doing the role badly — two dropped balls this month already. You've decided to resign now rather than limp to May. The message to the exec board needs to land as responsible, not flaky, and the timing needs to not torpedo the spring formal.","task":"Write the 3-4 sentence resignation: the decision with its date, the honest reason, and the transition plan.","tips":["Decision and effective date in sentence one — no 'I've been thinking a lot lately' runway.","One honest reason beats three defensive ones.","The transition plan is what makes it responsible: the formal's status, the handoff doc, your successor suggestion."],"focus":["clarity","structure"],"placeholder":"I'm stepping down as events coordinator, effective March 1 — I'm doing the role at half-capacity and the club deserves better."},
    {"id":"hard-stu-mid-09","level":"mid","profession":"student","title":"The data that didn't survive","scenario":"Your group's survey collected 200 responses — and you've just discovered a logic error in the form meant half of them never saw the key question. The professor's check-in is tomorrow. The group wants to quietly analyze the surviving 100 and not mention it. You're the one presenting, and you won't wear that.","task":"Write the 2-3 sentence disclosure you'd open with tomorrow: the problem, the size of the damage, the recovery plan.","tips":["Front-load the bad news with its number: a form error cost us half our responses.","No passive-voice fog — 'we misconfigured the form,' not 'an error occurred.'","Arrive with the recovery plan: what the surviving 100 still support, and the two-day re-collection option."],"focus":["clarity","precision"],"placeholder":"We found a form error that cost us half our responses — 100 of 200 never saw the key question. Here's what survives and how we recover:"},
    {"id":"hard-stu-mid-10","level":"mid","profession":"student","title":"Declining the offer you said yes to wanting","scenario":"Three weeks ago you told this startup's recruiter their internship was your top choice. Today a better offer arrived — better pay, better team, better city — and you're taking it. The decline email you owe the recruiter keeps deferring itself. Ghosting is the coward's version; the clean decline preserves a network you'll want at 25.","task":"Write the 3-sentence decline: the decision, brief gratitude with one specific, and the door left open.","tips":["Decide in sentence one: 'I've accepted another offer and am withdrawing.'","One specific thanks — the person who spent an hour with you — beats generic gratitude.","Don't over-explain the other offer; comparison details help nobody."],"focus":["clarity","audience"]},
    {"id":"hard-stu-mid-11","level":"mid","profession":"student","title":"Cutting the roster","scenario":"You captain the club's case-competition team, and regionals allows five competitors. Six people have been practicing for two months. The member you're cutting is the hardest worker and the weakest presenter, and he's going to ask 'why me' — a question that deserves a real answer, not 'it was really close.'","task":"Script the 3-sentence conversation opener: the decision, the honest reason, and what's true about his trajectory.","tips":["The decision first, unhedged — hope kills clean exits.","The reason must be the real one, stated kindly: presentation scoring is where we're thinnest, and that's his current gap.","Offer something real: the specific practice plan that changes this for next semester, if he wants it."],"focus":["clarity","impact"]},
    {"id":"hard-stu-mid-12","level":"mid","profession":"student","title":"Reporting what you saw","scenario":"You saw a group member paste a full page from an uncited source into your shared final paper. If it submits, the whole group is exposed. You've decided to tell the professor before the deadline — but your draft email reads like a prosecution: motive theories, character assessments, a demand for consequences.","task":"Rewrite it as 2-3 sentences: the facts you observed, the evidence location, and your bounded ask.","tips":["Report observations, not conclusions: what you saw, when, in which document version.","The version history is the evidence — point to it and stop.","Your ask is bounded: guidance before the deadline, not a verdict. Sentencing isn't your job."],"focus":["precision","clarity"]},
    {"id":"hard-stu-mid-13","level":"mid","profession":"student","title":"Leaving the lab","scenario":"You've worked in Professor Reyes's lab for a year, and she's invested real time in you. You're leaving — the new opportunity is a paid position in a lab closer to your actual interests. Your draft email buries the news under so much gratitude that the third paragraph's 'so unfortunately' lands like an ambush.","task":"Write the 3-sentence version: the news first, the specific gratitude, the responsible exit.","tips":["News in sentence one; gratitude lands better after honesty than before it.","Make the thanks specific — the conference she sent you to, the technique she taught you.","The exit logistics are the respect: your end date, the training-your-replacement offer, the state of your bench work."],"focus":["clarity","structure"],"placeholder":"I've accepted a paid position in the Chen lab starting next month, so I'll be leaving your group — and I want to say directly how much this year did for me."},
    {"id":"hard-stu-mid-14","level":"mid","profession":"student","title":"The no you owe a professor","scenario":"Your favorite professor just asked you to TA her course next semester. It's flattering, it's good for grad school — and it's fifteen hours a week you demonstrably don't have, on top of your thesis and your job. Yes-then-burnout would be worse for her course than a no today. Your draft keeps trying to say yes with conditions.","task":"Write the 2-3 sentence decline: the honest no, the real constraint, and the alternative if one exists.","tips":["A conditional yes you can't sustain is the worst answer — decide, then write.","Name the constraint concretely: thesis plus 12 shift-hours; she can verify the math.","If you'd genuinely do a smaller version — grading only, one section — offer exactly that and no more."],"focus":["clarity","concision"]},
    {"id":"hard-stu-mid-15","level":"mid","profession":"student","title":"The co-president conversation","scenario":"Your co-president announces decisions in the group chat that the two of you never made together — three times this month. Members are starting to ask which of you actually speaks for the club. The friendship matters; the pattern has to stop. You're raising it tonight, in person, before the next surprise.","task":"Script the 3-sentence opener: the pattern with instances, the impact on the club, the working agreement you're proposing.","tips":["Instances, not accusations: name the three announcements with dates.","The impact is institutional, not personal: members can't tell who speaks for the club — say that.","Propose the mechanism: nothing announced that both haven't approved in the planning doc. Concrete rules outlast good intentions."],"focus":["clarity","structure"]},
    {"id":"hard-stu-mid-16","level":"mid","profession":"student","title":"Cancelling on the vendors and the guests","scenario":"Ticket sales for the spring formal came in at 40 against a break-even of 120, and tonight the exec board voted to cancel. You're writing two messages tomorrow morning: one to the DJ and caterer (contracts, deposits), one to the 40 ticket-holders (refunds). Both drafts in your head start with three sentences of apology fog.","task":"Write the 2-3 sentence ticket-holder message: the cancellation first, the refund mechanics, and the honest one-line reason.","tips":["The news is the first five words, not the third paragraph.","Refund mechanics answer the reader's only real question: how much, back where, by when.","One honest reason ('sales couldn't cover costs') beats vague 'unforeseen circumstances' — students can smell fog."],"focus":["clarity","concision"],"placeholder":"The spring formal is cancelled. Your $25 refunds to your original payment method within 5 business days."},
    {"id":"hard-stu-mid-17","level":"mid","profession":"student","title":"The mentee's resume","scenario":"You mentor a first-year through the pre-business society, and he's just sent you his resume, visibly proud — 'already applied to six internships with it!' It has a typo in the header, three bullet points that are objectively just course names, and his high-school student council as the lead item. Kind lies now cost him the next six applications too.","task":"Write the 3-sentence response: the honest verdict delivered warmly, the two highest-impact fixes, the offer to work it together.","tips":["Honest and warm can coexist: 'This needs real work before the next application — and it's fixable this week.'","Prioritize ruthlessly: the header typo and the course-name bullets first; don't list all eleven problems.","End with the specific offer: thirty minutes Thursday, rewrite the top third together."],"focus":["audience","impact"]},
    {"id":"hard-stu-mid-18","level":"mid","profession":"student","title":"Your part will be late","scenario":"Your section of the group presentation is due to the team tonight, and it will not be ready — realistically, Thursday. You know the move here because you've been on the receiving end: the teammate who confessed at 11:58pm versus the one who flagged it two days early with a plan. Be the second one, now.","task":"Write the 2-sentence message: the slip with the new date first, then what you're doing to protect the group's timeline.","tips":["New date in sentence one — the group plans around dates, not around your guilt.","Protect their critical path: send the outline now so slide design can start.","No saga. The week you had is not information the group can use."],"focus":["clarity","impact"],"placeholder":"My section will be Thursday, not tonight — here's the outline now so slides can start, and Thursday is firm."},
    {"id":"hard-stu-mid-19","level":"mid","profession":"student","title":"Telling your advisor you're leaving the major","scenario":"Your advisor has spent two years championing you inside the chemistry department — research placement, conference funding, a grad-school plan. You're switching to computer science, and it's the right call. The meeting is Tuesday. Your fear of her disappointment is pushing the draft toward mush: 'exploring options, maybe, eventually.'","task":"Script the 2-3 sentence opener: the decision stated as decided, the through-line that honors her investment, and the ask.","tips":["Announce a decision, not a mood — 'I've decided to switch to CS' ends the ambiguity kindly.","Show the through-line: the computational side of her own lab is what pulled you — her investment led here.","Have an ask ready: her advice on finishing the chem minor, a reference — it tells her the relationship continues."],"focus":["clarity","audience"]},
    {"id":"hard-stu-mid-20","level":"mid","profession":"student","title":"The thesis doesn't hold","scenario":"Your writing-workshop partner's draft is due to the professor in a week, and after two careful reads you're sure: the thesis is contradicted by her own evidence in section three. Every other reviewer gave her comma edits. Telling her a week out is a gift; telling her gently-but-unmistakably is the skill.","task":"Write the 3-sentence core of your feedback: the problem stated plainly, the exact evidence of it, the salvage path.","tips":["Don't sandwich it into invisibility — the main point goes first and unmissable.","Show her the collision: the thesis says X; page 6's strongest example shows not-X. Quote both.","The salvage: her evidence actually supports a sharper, narrower thesis — name it. Critique that rebuilds is the kind that's welcome."],"focus":["clarity","impact"],"placeholder":"Before anything else: I think section 3's evidence contradicts your thesis — and I think your real thesis is hiding in there, one notch narrower."},
    {"id":"hard-stu-mid-21","level":"mid","profession":"student","title":"The funding request came back denied","scenario":"You championed the club's $1,500 request for the national conference trip, and the funding board just denied it. Five members have been planning around this trip for a month, two have already requested time off work. They find out tonight, from you, in the group chat you've been hyping the trip in.","task":"Write the 3-sentence message: the denial first, the stated reason, and the two real options that remain.","tips":["Bad news first, no wind-up: 'The board denied our conference funding.'","Pass through the board's actual reason — members deserve the real why, and you shouldn't wear a decision you didn't make.","Options keep it from being a funeral: the self-funded version's real cost, and the regional alternative. Name the decision meeting."],"focus":["clarity","structure"]},
    {"id":"hard-stu-mid-22","level":"mid","profession":"student","title":"The teammate who owes the pot","scenario":"Four of you fronted costs for the club's competition trip on the agreement of an even split. Two months later, one teammate still owes $85, and your two soft mentions ('no rush!') got smiles and nothing. The 'no rush' framing was the mistake — it converted a debt into a favor. Next message fixes that.","task":"Write the 2-sentence message: the specific amount and date expected, matter-of-fact, with a graceful out if there's hardship.","tips":["Numbers and dates make it business: '$85, by Friday, to any of our payment apps.'","Drop the apology reflexes — you're not sorry, and pretending otherwise re-blurs it.","One human clause: 'if the timing's genuinely hard, tell me and we'll set dates' — an out with structure, not an out with fog."],"focus":["clarity","precision"],"placeholder":"Following up on the trip split: $85, by Friday if you can."},
    {"id":"hard-stu-mid-23","level":"mid","profession":"student","title":"'I can't endorse you for this'","scenario":"A friend is running for club treasurer and asks you — the outgoing treasurer — to endorse him at the election meeting. He missed the budget training twice and lost the receipts you asked him to track at the fall event. You'd be lending your credibility to something you've watched not work. The no has to happen before the meeting, not at it.","task":"Script the 2-3 sentence conversation: the direct no, the specific and honest reason, and what you can genuinely offer.","tips":["'I can't endorse you' — complete sentence, delivered early enough for him to plan around.","The reason is the respect: the receipts and the trainings, named plainly, are things he can actually fix.","Genuine offers only: training him on the books regardless of the election outcome — if you mean it."],"focus":["clarity","impact"]},
    {"id":"hard-stu-mid-24","level":"mid","profession":"student","title":"The submission was rejected","scenario":"Your team's paper — four months of shared work — was rejected from the undergraduate research conference. The email with the reviews sits in your inbox, and you're the corresponding author. The team finds out from you. One review is harsh but fair; one is dismissive. Your job in the message: the news, straight, without editorializing the reviewers into villains.","task":"Write the 3-sentence team message: the rejection first, the honest gist of the reviews, and the concrete next step.","tips":["The word 'rejected' appears in sentence one — euphemisms ('unfortunately the committee...') just slow the landing.","Summarize the reviews honestly: one fixable methods critique, one dismissive — the team will read both anyway.","Point at the next decision, dated: revise for the spring venue, or submit the methods fix to the campus symposium. Meeting Thursday."],"focus":["clarity","structure"]},
    {"id":"hard-stu-mid-25","level":"mid","profession":"student","title":"Asking the professor to intervene","scenario":"Your four-person group is at week nine of a twelve-week project, and it is genuinely broken: one member has produced nothing despite two direct conversations, and the group's private workaround — doing his part — is now failing too. Going to the professor feels like tattling, so your draft is so hedged it reports nothing. It's not tattling; it's escalation, and it has a form.","task":"Write the 3-4 sentence email: the situation in one line, what the group already tried, the specific intervention you're requesting.","tips":["Open with the headline, not the history: 'Our group needs your help — we have a nonparticipation problem we can't solve internally.'","'What we already tried' is what separates escalation from complaint — two conversations, dates, the redistribution.","Ask for something specific: a group meeting with her, or guidance on the individual-grading clause. 'Just wanted to make you aware' wastes the ask."],"focus":["structure","clarity"],"placeholder":"Our project group needs your intervention: one member has contributed nothing through week nine, and we've exhausted what we can do internally."}
  ],
  "putting-it-together": [
    {"id":"together-stu-mid-01","level":"mid","profession":"student","title":"The complete extension request","scenario":"Everything converges: your grandmother's funeral is Thursday, your research paper is due Friday, and you need five days. The professor's syllabus says extensions are 'rarely granted, case by case.' This email needs everything you've practiced — the ask up front, the evidence, the precise new date, the register of an adult writing to an adult.","task":"Write the complete 4-sentence email.","tips":["Sentence one: the ask and the date. Sentence two: the reason, stated with dignity and without performance.","Include the verifiable: the obituary or dean-of-students note, offered not dumped.","Show control of the work: what's done, what remains, why five days is the real number.","Close with grace, not grovel."],"focus":["structure","audience"],"placeholder":"I'm requesting a five-day extension on the research paper, to Wednesday the 19th — my grandmother's funeral is this Thursday."},
    {"id":"together-stu-mid-02","level":"mid","profession":"student","title":"Sixty seconds at the booth","scenario":"Career fair, your target company's booth, the recruiter's badge says 'University Relations.' You get roughly sixty seconds before her eyes move to the line behind you. This is the whole toolkit in miniature: lead with the point, calibrate to her, one precise proof, and an ask that converts the minute into a next step.","task":"Script the 60-second introduction: who you are, one evidence-backed hook, and a specific ask — 4 sentences maximum.","tips":["She meets 200 students today; your first sentence decides whether she'll remember the other three.","One number she can repeat to a colleague: '400 students use the tool I built.'","The ask converts: not 'any advice?' but 'what should a data-intern application to you emphasize?'","End by making follow-up concrete: her name, the QR code, the thank-you note tonight."],"focus":["concision","impact"]},
    {"id":"together-stu-mid-03","level":"mid","profession":"student","title":"The recommendation package","scenario":"You're asking Professor Ibarra for a law-school recommendation, due in five weeks. A strong letter needs what she doesn't have: your materials, your memory-joggers, the logistics. The ask itself needs what you've practiced: the request up front, easy to say yes to, calibrated to a busy reader who writes ten of these a season.","task":"Write the complete email — the ask, the two memory anchors from her course, and the logistics — in 5 sentences.","tips":["Ask plus deadline in sentence one; 'would you be comfortable writing a strong letter' gives her a real out.","Anchor her memory to specifics: the paper topic she praised, the seminar debate you led.","Logistics in one tight block: portal link, deadline, resume and statement attached.","Offer the escape hatch graciously — a lukewarm letter hurts more than a no."],"focus":["structure","audience"],"placeholder":"Would you be comfortable writing a strong recommendation for my law school applications, due October 15?"},
    {"id":"together-stu-mid-04","level":"mid","profession":"student","title":"The cover letter, complete","scenario":"The posting is real: data analyst intern, city transit authority, 'strong communication skills required.' You have one page to do everything — open with a claim instead of throat-clearing, support it with two evidence-backed paragraphs, translate coursework into capability, and close with presence instead of pleading.","task":"Write the letter's skeleton: opening claim sentence, the two support-paragraph topic sentences, and the closing sentence.","tips":["The opening claim answers 'why you' before they ask — no 'I am writing to apply.'","Each support paragraph is one proof: the transit-data class project, the treasurer's budget you ran.","Match their language: they said 'communication' — show a moment you translated numbers for non-analysts.","Close forward: what you want to happen next, stated like someone who expects it to."],"focus":["structure","impact"]},
    {"id":"together-stu-mid-05","level":"mid","profession":"student","title":"The bookends of the talk","scenario":"Your capstone presentation is in a week: fifteen minutes on your semester's research into first-generation student retention. Audiences remember two moments — the first thirty seconds and the last thirty. Right now yours open with 'so, um, my project is about...' and end with 'yeah, so, that's basically it.'","task":"Write the opening 2 sentences and the closing 2 sentences as a matched pair.","tips":["Open with the finding or the tension — the title slide already said the topic.","The close is not a fade-out: restate the one-sentence takeaway and land the implication.","Bookend deliberately: the close should answer or echo the open.","Write these two moments word-for-word even if you improvise the middle."],"focus":["impact","structure"],"placeholder":"Open: First-generation students don't drop out at week ten because of grades — our data shows they leave earlier, and for a different reason."},
    {"id":"together-stu-mid-06","level":"mid","profession":"student","title":"The morning-after message","scenario":"Last night's club fundraiser double-charged eleven ticket-buyers — the payment form glitched, and the complaints are already in the club's inbox. You're sending the message to all attendees this morning. Bad news first, precise facts, a concrete fix with a date, and a register that's accountable without being groveling.","task":"Write the complete 4-sentence message.","tips":["Lead with what happened and who's affected — the eleven people already know; the rest deserve to hear it from you.","Precision is the apology: the exact error, the exact refund amount, the exact date it lands.","One sentence of ownership without theatrics; skip the three-paragraph apology essay.","Close with the channel for anyone still affected — one named person, not 'reach out anytime.'"],"focus":["clarity","precision"],"placeholder":"Last night's payment form double-charged 11 attendees — if you were charged twice, the duplicate $15 refunds by Friday, automatically."},
    {"id":"together-stu-mid-07","level":"mid","profession":"student","title":"The kickoff message that prevents the disaster","scenario":"New semester, new four-person project group, and you've lived the failure modes: the ghost, the deadline pileup, the 2am merge disaster. The first message to the group chat sets the culture. It needs structure (roles, dates, tools), audience awareness (peers, not subordinates), and enough brevity that people actually read it.","task":"Write the complete kickoff message in 5 sentences or fewer.","tips":["Claim the coordination role by doing it, not announcing it: propose, then ask for amendments.","Concrete beats aspirational: named roles, three internal deadlines, one shared doc — not 'let's communicate well.'","Peers need buy-in: end with a genuine 'what would you change?' and mean it.","Set the norm you'll need later: flag slips 48 hours early, no-fault."],"focus":["structure","audience"]},
    {"id":"together-stu-mid-08","level":"mid","profession":"student","title":"The 250-word essay","scenario":"The scholarship's final question: 'Why do you deserve this award?' — 250 words maximum. Everything converges in a tight box: an arc instead of a list, evidence instead of adjectives, the committee's criteria instead of your autobiography, and the cuts that concision demands.","task":"Write the essay's four structural sentences: the opening claim, the two evidence sentences, and the close.","tips":["The claim is your throughline, not 'I am honored to apply.'","Each evidence sentence: one concrete achievement with a number, tied to a stated criterion.","The close points forward — what the award becomes in your hands — not backward at your resume.","250 words is a concision exam; every adjective must fight for its life."],"focus":["structure","concision"]},
    {"id":"together-stu-mid-09","level":"mid","profession":"student","title":"Same news, two registers","scenario":"The news: your team's design won the department's innovation showcase, and there's $500 attached. You're telling two audiences in the next ten minutes — Professor Nguyen, who sponsored the entry, and your team group chat. Same facts, different registers, different emphasis: what she cares about is not what they care about.","task":"Write both messages: 2 sentences to the professor, then the group-chat version.","tips":["The professor invested her name: her version leads with the result and what her sponsorship produced.","The group version can celebrate — but still carries the facts: the amount, the ceremony date, the next step.","Register is more than tone: emphasis, length, and formality all shift — the facts don't.","Neither message should embarrass you if forwarded."],"focus":["audience","clarity"],"placeholder":"To Prof. Nguyen: Our team won the innovation showcase — thank you for sponsoring the entry; it wouldn't have been submitted without you."},
    {"id":"together-stu-mid-10","level":"mid","profession":"student","title":"The meeting sandwich","scenario":"Your thirty-minute advising meeting about graduate school is Tuesday. The full skill loop: an agenda email before (so she can prepare), and a summary email after (so decisions stick). Most students do neither, then wonder why advising feels useless. The before-email needs structure; the after-email needs precision about what was decided.","task":"Write both: the 2-sentence agenda email and the 3-sentence follow-up summarizing decisions and actions.","tips":["The agenda email is one scoped sentence per topic — GRE timing, the two target programs — so she walks in ready.","The summary email is the meeting's memory: each decision as a fact, each action with an owner and date.","'You said / I'll do' framing prevents the politest form of confusion.","Send the summary within 24 hours or it's fiction."],"focus":["structure","precision"]},
    {"id":"together-stu-mid-11","level":"mid","profession":"student","title":"The final two minutes","scenario":"The interviewer closes with the classic: 'Anything else you'd like us to know?' Most candidates waive it — 'no, I think we covered everything!' — surrendering the last word. You have two minutes to integrate the whole course: one governing claim, your two strongest proofs restated fresh, and a close with presence.","task":"Script the 4-sentence closing statement.","tips":["Treat it as your closing argument, prepared in advance — never improvised.","One claim ('the through-line of everything we discussed is...'), two proofs, one forward-looking close.","Restate, don't repeat: the same evidence in new words, sharpened by what you learned in the interview.","End on their future, not your past: what you'd do in the first month."],"focus":["impact","structure"],"placeholder":"One thing I'd add as a through-line: every example we discussed today is the same skill — taking something broken and unglamorous and making it work."},
    {"id":"together-stu-mid-12","level":"mid","profession":"student","title":"The document that outlives you","scenario":"You graduate in May, and the club's entire operational memory lives in your head: the room-booking workaround, the funding calendar, the vendor who needs three weeks' notice, the September mistake every new president makes. The handoff doc is your last act. It needs audience calibration (a reader with zero context), structure (findable, not chronological), and concision (or it won't be read).","task":"Write the doc's opening paragraph (2-3 sentences) and its five section headers.","tips":["The opening tells the successor how to use the doc — 'read section 1 before September; the rest is reference.'","Structure by their year, not your memory: First month, Funding deadlines, Events playbook, Contacts, Known traps.","Every claim precise enough to act on: names, dates, links — 'talk to facilities early' helps nobody.","Ask of each sentence: does this survive my absence?"],"focus":["structure","audience"]},
    {"id":"together-stu-mid-13","level":"mid","profession":"student","title":"The appeal, assembled","scenario":"Your final grade came back a C+ and your own arithmetic from the syllabus weights says B-. You've triple-checked. The formal appeal email is the whole toolkit under pressure: the claim up front, the evidence laid out so checking takes a minute, zero emotion in the register, and a bounded ask.","task":"Write the complete 4-sentence appeal email.","tips":["Sentence one is the claim and the ask: recorded C+, calculated B-, please re-check.","The evidence is a table in prose: each component, its weight, your score, the syllabus as source.","Strip every trace of grievance — arithmetic doesn't need an emotional co-signer.","Bound the ask: verify the calculation. Not 'reconsider my effort.'"],"focus":["precision","structure"],"placeholder":"I believe my final grade was miscalculated: the recorded grade is C+, but the syllabus weights applied to my scores yield a B-. Here's the arithmetic:"},
    {"id":"together-stu-mid-14","level":"mid","profession":"student","title":"Two minutes, any judge","scenario":"Symposium day. Judges rotate to your poster every few minutes, and the badge tells you nothing — this one might be a chemist, a dean, or a donor. Your two-minute walkthrough must integrate audience calibration (start universal, offer depth), structure (question, approach, finding, why-it-matters), and the precision to survive any follow-up.","task":"Script the four-beat walkthrough, one sentence per beat: the question, the approach, the finding, the significance.","tips":["Beat one is jargon-free by design — you don't know who's listening yet.","Offer the depth fork explicitly: 'happy to go into the method — or the implications, whichever interests you.'","The finding beat carries your one number; precision is what judges score.","Rehearse the two-minute version aloud; posters reward the practiced, not the comprehensive."],"focus":["audience","structure"]},
    {"id":"together-stu-mid-15","level":"mid","profession":"student","title":"The cold message and the follow-up","scenario":"The alum works exactly where you want to be in three years. Two messages decide whether this becomes a relationship: the cold LinkedIn note (short, specific, easy to accept) and the after-call follow-up (the thank-you that adds value instead of just closing the loop). Most students botch the second one with 'thanks so much!!' and vanish.","task":"Write both: the 3-sentence cold message and the 2-sentence follow-up after the call.","tips":["The cold note: connection, one specific reason it's her, one bounded ask — twenty minutes, her convenience.","The follow-up quotes the call: the specific advice you're acting on, and the action you took within 48 hours.","Acting on advice is the only thank-you that registers — it converts a favor into an investment.","Neither message exceeds a phone screen without scrolling."],"focus":["audience","concision"],"placeholder":"Follow-up: Your point about leading with the analytics certificate changed my resume the same night — the new version is attached."},
    {"id":"together-stu-mid-16","level":"mid","profession":"student","title":"The year, reported","scenario":"The annual general meeting, and as president you owe the club a year-in-review that isn't a highlight reel. The full integration: numbers instead of vibes (membership, budget, event outcomes — including the two failures), structure the room can follow, judgment separated from fact, and one clear ask for next year.","task":"Write the report's opening sentence, its three section headers, and the closing ask sentence.","tips":["Open with the honest headline: 'a growth year with two expensive lessons' beats 'an amazing year!'","Sections by what the audience decides on: Money, Membership, Events — each with its numbers, including the losses.","Mark your judgments as yours: 'my read is the Thursday slot, not the content.'","End with one ask the room can act on tonight: the vote, the volunteers, the budget line."],"focus":["structure","precision"]},
    {"id":"together-stu-mid-17","level":"mid","profession":"student","title":"Reading it as the grader","scenario":"Your discussion post is drafted, due in an hour. The last skill is the meta-skill: editing as the reader. Your professor grades forty of these against three rubric lines — argument, evidence, engagement with the text. Read your draft once as her: skimming, rubric in hand, deciding your grade in ninety seconds.","task":"Write the 3-question checklist you'd run on the draft, each question tied to how the grader actually reads.","tips":["Question one is always: can she find the claim in the first two lines, skimming?","Check evidence as she would: is every textual claim anchored to a page or passage she can verify?","Read your first sentence and your last — the two she'll definitely read — do they carry the argument alone?","This checklist is transferable: every document has a grader; find yours before sending."],"focus":["audience","structure"],"placeholder":"1. Skimming the first two lines only — is my actual claim visible, or just topic-throat-clearing?"},
    {"id":"together-stu-mid-18","level":"mid","profession":"student","title":"The sponsor recovery","scenario":"The local bookstore sponsored your club's author night — $300 and their name on everything — and your team botched the logistics: the projector failed and the event started forty minutes late. The owner was there, visibly unimpressed. The recovery email must integrate hard-message delivery, precision about the fixes, and the audience awareness that she's a businessperson deciding whether you're worth a second bet.","task":"Write the complete 4-sentence email: ownership, the specific fixes for next time, what her sponsorship still bought, and the re-invitation.","tips":["Own it in sentence one, factually: forty minutes late, and it was our failure, not the venue's.","The fix list is the actual apology: AV check 24 hours before, a named tech lead, a backup projector.","Give her the real numbers her money bought — 60 attendees stayed, 22 signed her mailing list — sponsors think in returns.","Re-invite with the risk removed: next event, zero cost, see the fixes yourself."],"focus":["audience","precision"]},
    {"id":"together-stu-mid-19","level":"mid","profession":"student","title":"The application essay under everything","scenario":"The study-abroad program in Seoul takes 20 of 90 applicants, and the 400-word statement is the differentiator. Full integration: the committee's criteria as your frame (academic purpose, maturity, ambassadorship), an arc instead of a wishlist, evidence instead of enthusiasm, and the concision that 400 words enforces.","task":"Write the statement's four load-bearing sentences: the opening, one for each of the two criteria you'll evidence, and the close.","tips":["Open inside your academic story, not inside your travel dreams — the committee funds coursework, not wanderlust.","Each criterion gets evidence, not assertion: the Korean coursework completed, the two courses only Yonsei offers.","Maturity is shown by planning: name the credit-transfer plan and the budget — one clause each.","Close as an ambassador: what you bring back, specifically, and to whom."],"focus":["audience","structure"]},
    {"id":"together-stu-mid-20","level":"mid","profession":"student","title":"The dues increase","scenario":"The exec board voted: dues rise from $20 to $35 next semester — the first increase in six years, forced by real costs. You're writing the announcement to 60 members, some of whom will genuinely feel $15. Everything applies: bad news first, the arithmetic in the open, the objection pre-empted, and the hardship path stated without stigma.","task":"Write the complete 4-sentence announcement.","tips":["The number leads: '$35 next semester, up from $20' — burying it in paragraph three is where trust dies.","Show the math that forced it: venue costs up 40%, the subsidy that ended — two facts, no essay.","Pre-empt 'what do I even get': one line on what dues bought last semester, concretely.","The hardship line is one sentence, normalized: 'confidential fee waiver, message me, no questions.'"],"focus":["clarity","audience"],"placeholder":"Dues will be $35 next semester, up from $20 — here's exactly why and what it pays for."},
    {"id":"together-stu-mid-21","level":"mid","profession":"student","title":"The thank-you that keeps arguing","scenario":"The interview ended three hours ago, and one moment nags: the case question about declining users, where you gave half an answer. The thank-you email is the last touch. The integration: concision (it's a note, not a letter), audience awareness (she's deciding this week), and the advanced move — one sentence that completes your half-answer without re-litigating the interview.","task":"Write the complete 3-sentence email.","tips":["Sentence one: thanks anchored to one specific exchange, proving presence.","Sentence two is the redemption move: 'One addition to the retention question...' — the sharpened answer in one line.","Do it once; a list of corrections reads as anxiety, a single sharp addition reads as reflection.","Send same-day: the note should land while you're still a face."],"focus":["concision","impact"],"placeholder":"One addition to the retention question: I'd start with the cancellation-survey data — the users tell you which lever matters before you test anything."},
    {"id":"together-stu-mid-22","level":"mid","profession":"student","title":"The semester letter to your mentor","scenario":"Your alumni mentor gets one email from you per semester — this is it. It needs everything at once: a headline (not a diary), structure she can skim in a minute, precise numbers where they exist, and the one bounded ask that respects the relationship's currency. Last semester's version was six paragraphs; she replied with two lines a month later.","task":"Write the complete email in 5 sentences: headline, two update lines with numbers, the ask, the close.","tips":["Headline the semester in one line: the internship secured, the GPA, the pivot — whichever leads.","Two updates maximum, each with its number; the rest waits for the call.","One ask, bounded and answerable in five minutes: the intro, the resume look, the yes/no question.","End with reciprocity — one line acting on her last advice. Mentors continue investing where they see returns."],"focus":["structure","concision"]},
    {"id":"together-stu-mid-23","level":"mid","profession":"student","title":"From chaos to record","scenario":"The end-of-semester planning meeting just ended: 90 minutes, seven people, decisions and half-decisions tangled through arguments and tangents. Your notebook has it all, unsorted. By tonight, the group needs the record — and the record IS the communication skill: what was decided (fact), what's assigned (name, date), what stays open (honest), all findable in thirty seconds.","task":"Write the summary message: a one-line header plus the three labeled sections with one entry each.","tips":["Decisions are written as settled facts — re-litigable phrasing ('we sort of agreed...') reopens every fight.","No action item without a name and a date; unowned items are how groups fail politely.","Open questions get listed, not resolved by the note-taker — that's honesty about where the meeting actually ended.","The test: someone who missed the meeting acts correctly from this alone."],"focus":["structure","precision"],"placeholder":"DECIDED: Spring showcase is April 9, Hensley Hall. ASSIGNED: Venue contract — Dana, by Friday."},
    {"id":"together-stu-mid-24","level":"mid","profession":"student","title":"The public version","scenario":"Your capstone team just shipped its project — a food-access map now used by two local nonprofits — and you're writing the LinkedIn post. Public register is its own discipline: confident without bragging, specific without jargon, crediting the team while owning your part, readable by a recruiter, a professor, and your aunt simultaneously.","task":"Write the complete 4-sentence post.","tips":["Lead with the outcome anyone can picture: two nonprofits route food deliveries with it — not your tech stack.","Own your part in one honest clause ('I built the data pipeline'), credit the team by name in another.","One number for the recruiters skimming: the datasets merged, the users, the weeks.","Close with reflection or invitation, not hashtag soup — one line that sounds like a person."],"focus":["audience","impact"]},
    {"id":"together-stu-mid-25","level":"mid","profession":"student","title":"The first paragraph of the biggest ask","scenario":"The personal statement, graduate applications, 500 words — and the first paragraph decides whether a tired admissions reader leans in or skims. Every cliché is a landmine: the childhood dream, the dictionary definition, the 'ever since I can remember.' What you've practiced all course is the alternative: a specific scene, a real question, an earned claim.","task":"Write the complete opening paragraph in 3-4 sentences: the concrete hook, the question it raised, and the thesis of your candidacy.","tips":["Start inside a specific moment with a date, a place, a problem — scenes are unfakeable; abstractions aren't.","The hook must generate the question your academic story answers — decoration that connects to nothing gets cut.","By the last sentence, the reader knows your claim: what you're for, in one line.","Read it aloud in the voice of someone on their fortieth application of the night — survive that reader."],"focus":["impact","structure"],"placeholder":"The night the food pantry's spreadsheet crashed — finals week, 300 families in the queue — I rebuilt it by hand and realized the problem wasn't the data."}
  ],
};
